impl Op for SqrtPlusOne {
    fn name(&self) -> &'static str {
        "sqrt_plus_1"
    }

    fn arity(&self) -> u8 {
        1
    }

    fn eval(&self, args: &[f64]) -> Option<f64> {
        if args.is_empty() {
            return Some(1.0);
        }
        let x = args[0];
        if x < 0.0 {
            None // Cannot compute sqrt of negative number
        } else {
            Some(x.sqrt() + 1.0)
        }
    }

    fn generate_random(rng: &mut impl Rng, max_depth: u8) -> Self {
        SqrtPlusOne
    }

    fn mutate(&self, rng: &mut impl Rng, max_depth: u8) -> Self {
        *self
    }

