[dependencies]",
  "main.rs": "fn tokenize(input: &str) -> Vec<String>
{
    let mut tokens = Vec::new();
    let mut current_token = String::new();
    let mut in_quote = false;

    for ch in input.chars()
    {
        match (ch, in_quote)
        {
            // Space outside quotes - token separator
            (' ', false) =>
            {
                if !current_token.is_empty()
                {
                    tokens.push(std::mem::take(&mut current_token));
                }
            }
            // Space inside quotes - keep it
            (' ', true) =>
            {
                current_token.push(ch);
            }
            // Single quote toggles state
            (''', _) =>
            {
                in_quote = !in_quote;
                // Quote itself is not included in token
            }
            // Regular character
            (_, _) =>
            {
                current_token.push(ch);
            }
        }
    }

    // Push remaining token if any
    if !current_token.is_empty()
    {
        tokens.push(current_token);
    }

    tokens
}

pub fn main()
{
    let test_cases = vec![
        (" one  ' two  'three    four", vec!["one", " two  three", "four"]),
        ("'hello' world", vec!["hello", "world"]),
        ("  leading space", vec!["leading", "space"]),
        ("noquotes", vec!["noquotes"]),
        ("  ", vec![]),
    ];

    for (input, expected) in test_cases
    {
        let result = tokenize(input);
        println!("Input: `{}`", input);
        println!("Result: {:?}", result);
        println!("Expected: {:?}\n", expected);
        assert_eq!(result, expected, "Failed for: {}", input);
    }

    // Run interactive demo from the task description
    println!("Interactive demo:");
    tokenize(" one  ' two  'three    four")
        .iter()
        .for_each(|a| println!("`{}\"", a));
}

