impl<'de> serde::de::Visitor<'de> for CharacterVisitor {
    type Value = Character;

    fn expecting(&self, formatter: &mut std::fmt::Formatter) -> std::fmt::Result {
        formatter.write_str("a character object")
    }

    fn visit_map<V>(self, mut map: V) -> Result<Character, V::Error>
    where
        V: serde::de::MapAccess<'de>,
    {
        let mut name: Option<String> = None;
        let mut ac: Option<u8> = None;
        let mut hp: Option<u16> = None;

        while let Some(key) = map.next_key::<String>()? {
            match key.as_str() {
                "name" => name = Some(map.next_value()?),
                "ac" => ac = Some(map.next_value()?),
                "hp" => hp = Some(map.next_value()?),
                _ => {
                    let _: serde::de::IgnoredAny = map.next_value()?;
                }
            }
        }

        Ok(Character {
            name: name.ok_or_else(|| serde::de::Error::missing_field("name"))?,
            ac: ac.ok_or_else(|| serde::de::Error::missing_field("ac"))?,
            current: hp.ok_or_else(|| serde::de::Error::missing_field("hp"))?,
            max: hp.ok_or_else(|| serde::de::Error::missing_field("hp"))?,
            temp: 0,
