// Helper function to get nested JSON value by dot-separated path
fn get_nested_value(value: &Value, path: &str) -> Result<Value, String> {
    if path.is_empty() {
        return Ok(value.clone());
    }

    let keys: Vec<&str> = path.split('.').collect();
    let mut current = value;

    for key in keys {
        match current {
            Value::Object(map) => {
                current = map.get(key).ok_or_else(|| format!("Key '{}' not found", key))?;
            }
            _ => return Err("Path traversal failed".to_string()),
        }
    }

    Ok(current.clone())
}

// Wrapper for handling $ref resolution
#[derive(Debug)]
struct MaybeRef<T> {
    value: T,
}

impl<'de, T: Deserialize<'de>> Deserialize<'de> for MaybeRef<T> {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        let value = Value::deserialize(deserializer)?;

        match value {
            Value::Object(map) => {
                if let Some(ref_value) = map.get("$ref") {
                    let ref_path = ref_value
                        .as_str()
                        .ok_or_else(|| serde::de::Error::custom("$ref must be a string"))?;

                    // Parse the reference (format: ./file.json#/path/to/field)
                    let parts: Vec<&str> = ref_path.split('#').collect();
                    let file_path = parts[0];
                    let json_path = if parts.len() > 1 && !parts[1].is_empty() {
                        &parts[1][1..]
                    } else {
                        ""
                    };

                    // Load the referenced file
                    let ref_content = fs::read_to_string(file_path)
                        .map_err(|e| serde::de::Error::custom(format!("Failed to read ref file: {}", e)))?;

                    let ref_value: Value = serde_json::from_str(&ref_content)
                        .map_err(|e| serde::de::Error::custom(format!("Failed to parse ref file: {}", e)))?;

                    // Navigate to the path
                    let target = if json_path.is_empty() {
                        ref_value
                    } else {
                        get_nested_value(&ref_value, json_path)?
                    };

                    // Convert to target type
                    let resolved = T::deserialize(target)
                        .map_err(|e| serde::de::Error::custom(format!("Type conversion failed: {}", e)))?;

                    Ok(MaybeRef { value: resolved })
                } else {
                    let v = T::deserialize(value)
                        .map_err(|e| serde::de::Error::custom(e))?;
                    Ok(MaybeRef { value: v })
                }
            }
            _ => {
                let v = T::deserialize(value)
                    .map_err(|e| serde::de::Error::custom(e))?;
                Ok(MaybeRef { value: v })
            }
        }
    }
}

#[derive(Deserialize, Debug)]
struct A {
