    path_list: Vec<PathBuf>,
}

fn deserialize_maybe_ref_vec<'de, D>(deserializer: D) -> Result<Vec<PathBuf>, D::Error>
where
    D: Deserializer<'de>,
{
    let value = serde_json::Value::deserialize(deserializer)?;

    match value {
        Value::Array(arr) => {
            let mut result = Vec::new();
            for item in arr {
                let maybe_ref: MaybeRef<String> = serde_json::from_value(item)
                    .map_err(|e| serde::de::Error::custom(format!("Deserialization failed: {}", e)))?;
                result.push(PathBuf::from(maybe_ref.value));
            }
            Ok(result)
        }
        Value::Object(map) => {
            // Single $ref at top level
            if let Some(ref_value) = map.get("$ref") {
                let ref_path = ref_value
                    .as_str()
                    .ok_or_else(|| serde::de::Error::custom("$ref must be a string"))?;

                let parts: Vec<&str> = ref_path.split('#').collect();
                let file_path = parts[0];
                let json_path = if parts.len() > 1 && !parts[1].is_empty() {
