                    result.push(PathBuf::from(maybe_ref.value));
                }

                Ok(result)
            } else {
                Err(serde::de::Error::custom("Invalid structure, expected $ref"))
            }
        }
        _ => Err(serde::de::Error::custom("Expected array or object with $ref")),
    }
}

