use std::future::Future;
use std::sync::mpsc::{channel, Receiver, Sender};

#[derive(Debug)]
pub struct Context(i32);

// Helper trait to convert AsyncFnOnce into a wrapped Future
pub trait IntoSendableFuture {
    fn into_sendable_future(self) -> Pin<Box<dyn Future<Output = ()> + Send>>;
}

// Implementation for any closure that implements FnOnce(&mut Context)
// Returns a boxed, pinned Future that is guaranteed Send
impl<T, F> IntoSendableFuture for T
where
    T: FnOnce(&mut Context) -> F + Send + 'static,
    F: Future<Output = ()> + Send + 'static,
{
    fn into_sendable_future(self) -> Pin<Box<dyn Future<Output = ()> + Send>> {
        Box::pin(async move {
            // Create the context here for proper capture
            let ctx = Context(0);
            let result = self(ctx).await;
            drop(result);
        })
    }
}

// Simplified event enum for demonstration
#[derive(Debug)]
pub enum InnerAsyncEvent {
    DoWithContext(Pin<Box<dyn Future<Output = ()> + Send>>),
}

pub fn with_context_async(
    mut work_sender: Sender<InnerAsyncEvent>,
    block: impl FnOnce(&mut Context) -> impl Future<Output = ()> + Send + 'static,
) {
    let fut: Pin<Box<dyn Future<Output = ()> + Send>> = Box::pin(async move {
        let mut ctx = Context(0);
        let result = block(&mut ctx).await;
        drop(result);
    });

    let _ = work_sender.send(InnerAsyncEvent::DoWithContext(fut));
}

#[tokio::main]
