    let (tx, rx): (Sender<InnerAsyncEvent>, Receiver<InnerAsyncEvent>) = channel();

    // Start worker thread
    let _handle = std::thread::spawn(move || {
        while let Ok(event) = rx.recv() {
            match event {
                InnerAsyncEvent::DoWithContext(mut fut) => {
                    println!("Worker received event, executing...");
                    tokio::runtime::Handle::current().block_on(async move {
                        fut.await;
                    });
                    println!("Worker finished execution.");
                }
            }
        }
    });

    println!("Main sending async workload via channel...");

