fn try_poll<'a, X>(future: Pin<&'a mut dyn Future<Output = X>>) -> Poll<X> {
    let waker = Arc::new(NoopWaker::new());
    let mut cx = Context::from_waker(&waker as &Waker);
    future.poll(&mut cx)
}

enum TryPollResult<X> {
    Ready(X),
    Pending(Pin<Box<dyn Future<Output = X> + Send>>),
}

fn try_poll_one_time<X>(mut future: Pin<Box<dyn Future<Output = X> + Send>>) -> TryPollResult<X>
where
    X: Send + 'static,
{
    match try_poll(future.as_mut()) {
        Poll::Ready(value) => TryPollResult::Ready(value),
        Poll::Pending => TryPollResult::Pending(future),
    }
}

#[tokio::main]
async fn main() {
    // Example 1: Instantly ready future
    println!("Example 1: Ready future");
    let result = process_future(Box::pin(async { 42 })).await;
    println!("Got value: {}\n", result);

    // Example 2: Delayed future
    println!("Example 2: Delayed future");
    let result = process_future(Box::pin(tokio::time::sleep(tokio::time::Duration::from_secs(2))).await).await;
    println!("Sleep completed: {:?}\n", result);

    // Example 3: Using a custom delayed future
    println!("Example 3: Custom delayed future");
    let result = process_future(Box::pin(demo_delayed_future())).await;
    println!("Delayed result: {}\n", result);
}

async fn process_future<X>(future: Pin<Box<dyn Future<Output = X> + Send>>) -> Option<X>
where
    X: Send + 'static,
{
