serde_json = "1.0"",
  "main.rs": "use serde::Deserialize;

#[derive(Debug, Deserialize)]
struct Server {
    name: String,
}

#[derive(Debug)]
struct Character {
    name: String,
    server: String,
}

impl<'de> Deserialize<'de> for Character {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: serde::Deserializer<'de>,
    {
        #[derive(Deserialize)]
        #[serde(field_identifier, rename_all = "lowercase")]
        enum Field {
            Name,
            Server,
        }

        struct CharacterVisitor;

        impl<'de> serde::de::Visitor<'de> for CharacterVisitor {
            type Value = Character;

            fn expecting(&self, formatter: &mut std::fmt::Formatter) -> std::fmt::Result {
                formatter.write_str("a character object")
            }

            fn visit_map<A>(self, mut map: A) -> Result<Character, A::Error>
            where
                A: serde::de::MapAccess<'de>,
            {
                let mut name: Option<String> = None;
                let mut server_name: Option<String> = None;

                while let Some(key) = map.next_key::<Field>()? {
                    match key {
                        Field::Name => {
                            if name.is_some() {
                                return Err(serde::de::Error::duplicate_field("name"));
                            }
                            name = Some(map.next_value()?);
                        }
                        Field::Server => {
                            if server_name.is_some() {
                                return Err(serde::de::Error::duplicate_field("server"));
                            }
                            let s: Server = map.next_value()?;
                            server_name = Some(s.name);
                        }
                    }
                }

                Ok(Character {
                    name: name.ok_or_else(|| serde::de::Error::missing_field("name"))?,
                    server: server_name
                        .ok_or_else(|| serde::de::Error::missing_field("server"))?,
                })
            }
        }

        const FIELDS: &[&str] = &["name", "server"];
        deserializer.deserialize_struct("Character", FIELDS, CharacterVisitor)
    }
}

fn main() {
    let json_str = r#"{
        "name": "Name",
        "server": {
            "name": "Server"
        }
    }"#;

    let char: Character = serde_json::from_str(json_str).expect("Failed to deserialize");

    println!("Character: {:?}", char);
}
"
