// Trait representing various stages of the proxy lifecycle
#[async_trait::async_trait]
pub trait ProxyStage {
    async fn process(&self, ctx: &mut RequestContext);
}

// Common context passed through the lifecycle
struct RequestContext {
    request_span: tracing::Span,
}

impl RequestContext {
    fn with_parent(span: tracing::Span) -> Self {
        RequestContext { request_span: span }
    }
