struct HttpHandler;

#[allow(async_fn_in_trait)] // Not actually async_trait crate in minimal example, inline implementation
impl ProxyStage for HttpHandler {
    async fn process(&self, ctx: &mut RequestContext) {
        // CRITICAL STEP: Rehydrate the parent span context for this execution flow.
        // Without this, child spans created here would not be nested under Request Span.
        let _guard = ctx.request_span.enter();

        let _stage_span = info_span!("Stage_1", method = "HTTP");
        let _entered = _stage_span.enter();

        info!("Processing HTTP request...");

        // Simulate upstream communication
        let _upstream_span = info_span!("Upstream_Calls", target = "api-gateway");
        let _u_entered = _upstream_span.enter();
        sleep(Duration::from_millis(10)).await;
        info!("Upstream response received");
    }
}

// Another Stage implemented similarly
struct AuthValidator;

impl ProxyStage for AuthValidator {
    async fn process(&self, ctx: &mut RequestContext) {
        // Again, attach parent context before creating own scopes
        let _guard = ctx.request_span.enter();

        let _auth_span = info_span!("Stage_Auth", validate = true);
        let _a_entered = _auth_span.enter();

        sleep(Duration::from_millis(15)).await;
        info!("Authentication completed");
    }
}

