async fn run_lifecycle(stages: Vec<Box<dyn ProxyStage>>, ctx: &mut RequestContext) {
    info!("Lifecycle started");
    for stage in stages {
        // Calling stages from any thread/context requires explicit context restoration
        // Using our stored span handle to re-attach the trace context
        stage.process(ctx).await;
        sleep(Duration::from_millis(5)).await;
    }
    info!("Lifecycle ended");
}

