// Demonstrates handling global mouse events (drag logic) with fine-grained reactivity.
// Uses Context to pass State Signals between components without rebuilding the entire tree.

#![allow(unused_imports, unused_variables)]

use dioxus::prelude::*;
use std::collections::HashMap;

/// Represents a coordinate in screen space
#[derive(Clone, Copy, Debug)]
pub struct Point(f32, f32);

impl Point {
    fn new(x: f32, y: f32) -> Self {
        Point(x, y)
    }
}

/// Shared Drag State held in Context
/// Contains reactive Signals rather than raw values to allow efficient updates
pub struct DragState {
    pub mouse_pos: Signal<Point>,
    pub is_dragging: Signal<bool>,
    pub active_id: Signal<Option<u64>>,
}

impl DragState {
    /// Creates a new DragState instance for the context provider
    fn new() -> Self {
        DragState {
            mouse_pos: Signal::new(Point(0.0, 0.0)),
            is_dragging: Signal::new(false),
            active_id: Signal::new(None),
        }
    }
}

/// Wrapper Component that sets up the global drag state
#[component]
fn DragProvider(children: Element) -> Element {
    // Initialize context value using ContextProvider
    // We create the signals here so they persist across renders
    let mut state = use_context_provider(DragState::new);

    rsx! {
        div {
            style: "width: 100%; height: 100%; overflow: hidden; background-color: #f0f0f0; position: relative;",
            id: "world",
            // Global listeners update the shared Signal
            onmousemove: move |evt| {
                state.mouse_pos.update(|p| *p = evt.element_coordinates());
            },
            onmousedown: move |evt| {
                state.is_dragging.update(|d| *d = true);
            },
            onmouseup: move |_| {
                state.is_dragging.update(|d| *d = false);
            },
            onmouseleave: move |_| {
                state.is_dragging.update(|d| *d = false);
            },
            // Render the children (the actual draggable items)
            {children}
        }
    }
}

#[derive(PartialEq)]
struct PointProps {
    id: u64,
    initial_x: f32,
    initial_y: f32,
    r: f32,
}

/// Individual Point Component
/// Reactively updates only when relevant signals change
#[component]
fn Point(props: PointProps) -> Element {
    // Subscribe to the global drag state context
    let state = use_context::<DragState>();

    // Local state for the specific point's position
    // We start at initial props, but can be overridden by drag logic
    let mut position = use_signal(|| Point::new(props.initial_x, props.initial_y));

    let drag_active = state.read().active_id;

    // Determine visual state based on context
    // Only compute what we need in the render function
    let is_current_point = *drag_active.read() == Some(props.id);
    let is_dragging = *state.read().is_dragging;
    let current_mouse = *state.read().mouse_pos;

    // Update position if we are the active drag target and currently dragging
    if is_dragging && is_current_point {
        // Adjust position to follow mouse
        // In a real implementation, you'd subtract offset (center of circle)
        position.set(current_mouse);
    }

    // Style calculation
    let stroke_color = if is_current_point { "red" } else { "black" };
    let fill_color = if is_current_point { "orange" } else { "white" };

    rsx! {
        circle {
