impl<S> tower::Service<axum::extract::Request<S>> for ValidatedOrigin {
    type Response = Self;
    type Error = (StatusCode, String);
    type Future = std::future::Ready<Result<Self, Self::Error>>;

    fn poll_ready(
        &mut self,
        _cx: &mut std::task::Context<'_>,
