/// Parses various LanceDB ISO string formats back into UNIX timestamps.
/// Handles both strings with and without fractional seconds (e.g., '....00' vs '....409').
pub fn parse_lancedb_timestamp(date_str: &str) -> Result<i64, Box<dyn Error>> {
    // Try parsing with fractional seconds first (matches '%.f' requiring >= 1 digit)
    if let Ok(dt) = NaiveDateTime::parse_from_str(date_str, "%Y-%m-%dT%H:%M:%S%.f") {
        return Ok(dt.and_utc().timestamp());
    }

    // Fallback to parsing without fractional seconds
    if let Ok(dt) = NaiveDateTime::parse_from_str(date_str, "%Y-%m-%dT%H:%M:%S") {
        return Ok(dt.and_utc().timestamp());
