    pub fn new<N>(container_name: N, db_config: DbConfig) -> Self
    where
        N: Into<String>,
    {
        Self {
            admin_client: OnceCell::new(),
            db_config,
        }
    }

    /// Returns the cached admin client (connected to default postgres DB).
    /// Creates a new connection if none exists.
    async fn get_admin_client(&self) -> Result<std::sync::Arc<Client>, tokio_postgres::Error> {
        let client_ref = self.admin_client.get_or_init(self.init_admin_connection()).await?;
        Ok(std::sync::Arc::clone(client_ref))
    }

    async fn init_admin_connection(&self) -> Result<std::sync::Arc<Client>, tokio_postgres::Error> {
        let conn_str = format!(
            "host=localhost port={} user=postgres password={}",
            self.db_config.port, self.db_config.postgres_password
        );

        let (client, conn) = tokio_postgres::connect(&conn_str, NoTls).await?;

        // Crucial: Spawn the connection future. It must not be dropped while the client exists.
        tokio::spawn(async move {
            if let Err(e) = conn.await {
                eprintln!("Admin connection error: {}", e);
            }
        });

        // Wrap in Arc to ensure it persists and is shared safely
        Ok(std::sync::Arc::new(client))
    }

    pub async fn create_database(&self, name: &str) -> Result<(), tokio_postgres::Error> {
        let client = self.get_admin_client().await?;

        // CREATE DATABASE
        client
            .execute(&format!("CREATE DATABASE \"{}\"", name), &[])
            .await?;

        // Connect to specific DB to run schema
        let mut conn_str = format!(
            "host=localhost port={} user=postgres password={}",
            self.db_config.port, self.db_config.postgres_password
        );
        conn_str.push_str(&format!(" dbname={} ", name));

        let (client, conn) = tokio_postgres::connect(&conn_str, NoTls).await?;
        tokio::spawn(async move {
            if let Err(e) = conn.await {
                eprintln!("DB connection error: {}", e);
            }
        });

        // Load and execute schema
        // load_schema() simplified for demo:
        client.batch_execute("SELECT 1;").await?;

        Ok(())
    }

    pub async fn drop_database(&self, name: &str) -> Result<u64, tokio_postgres::Error> {
        let client = self.get_admin_client().await?;

        // Terminate all connections to target DB
        let terminate_sql = format!(
            r#"
            SELECT pg_terminate_backend(pid)
            FROM pg_stat_activity
            WHERE datname = '\''{}\''' AND pid <> pg_backend_pid();
            "#,
            name
        );

        client.execute(&terminate_sql, &[]).await?;

        // Drop Database
        client.execute(&format!("DROP DATABASE \"{}\"", name), &[]).await
    }
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // NOTE: This example requires a running Postgres instance on localhost:5432.
    // If running this without a DB, expect connection errors in logs.
    println!("Starting Pg Cache Test...");

    let config = DbConfig {
        port: 5432,
        name: "test_db".to_string(),
        user: "postgres".to_string(),
        postgres_password: "password".to_string(),
        db_password: "password".to_string(),
    };

    let container = DbContainer::new("my-test-container", config);

