        Ok(_) => println!("Database created successfully."),
        Err(e) => {
            // Connection failures are expected if no DB is running locally
            eprintln!("Create DB failed (expected if no Postgres): {}", e);
        }
    }

    match container.drop_database("demo_db").await {
        Ok(rows) => println!("Database dropped. Rows affected: {}", rows),
        Err(e) => {
             eprintln!("Drop DB failed (expected if not exists/no Postgres): {}", e);
        }
    }

    // Force program to live long enough to see any connection cleanup logs if desired
    tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
    println!("Test runner finished.");

    Ok(())
}"
