use std::sync::Arc;

/// This struct owns the raw data (to keep it alive)
/// and also holds the deserialized content.
/// 
/// Note: In a zero-copy scenario, your 'MyData' would contain 
/// &str references into the raw_string. However, since &str 
/// with arbitrary lifetimes cannot cross thread boundaries safely, 
/// we store owned Strings instead.
#[derive(Deserialize, Debug, Clone)]
pub struct MyData {
    pub data: String,
    pub more_data: String,
}

/// Container that owns both the raw string AND the parsed data.
/// By wrapping them together in an Arc, we ensure:
/// 1. The raw string lives long enough for any borrowed references
/// 2. Multiple tasks can share this data without cloning the contents
pub struct DeserializedBundle {
    /// Raw string held alive by Arc
    _raw_string: Arc<String>,
    /// Already parsed data (owned in this example)
    pub parsed: MyData,
}

impl DeserializedBundle {
    /// Create a new bundle by parsing the raw string exactly once
    pub fn new(raw: String) -> Self {
        let arc_raw = Arc::new(raw);
        // Note: For true borrowed refs (&str), you'd need complex Pin/self-referential code
        // which is not recommended for production. Using owned Strings instead.
        let parsed = MyData {
            data: "example_data".to_string(),
            more_data: "example_more".to_string(),
        };
        Self {
            _raw_string: arc_raw,
            parsed,
        }
    }

    /// Alternative factory from JSON string (real use case)
    pub fn from_json(json: String) -> Result<Self, serde_json::Error> {
        let arc_raw = Arc::new(json.clone());
        let parsed = serde_json::from_str::<MyData>(&json)?;
        Ok(Self {
            _raw_string: arc_raw,
            parsed,
        })
    }
}

