    println!("   Raw string length: {} chars", bundle._raw_string.len());
    println!("   Parsed data: {:?}", bundle.parsed);

    // Step 2: Wrap in Arc for safe sharing across threads
    let shared_bundle = Arc::new(bundle);

    // Step 3: Spawn multiple tasks that all receive the SAME Arc
    // Each gets a clone of the Arc (cheap!) but shares the same underlying data
    let handles: Vec<_> = (0..3)
        .map(|i| {
