}

fn namedvalue_property(_ui: &mut egui::Ui, _title: &str, _v: &mut (), _interactable: bool) {}
fn argnamedvalue_property(_ui: &mut egui::Ui, _title: &str, _v: &mut (), _interactable: bool) {}

// Generic list handler
pub fn list_property<T: Default + 'static>(ui: &mut egui::Ui, title: &str, value_mut: &mut Vec<T>, interactable: bool) {
    egui::CollapsingHeader::new(title)
        .default_open(true)
        .enabled(interactable)
        .show(ui, |ui| {
            ui.horizontal_top(|ui| {
                if ui.button("➕ Add").clicked() {
