/// Wraps the syslog logger to centralize error handling and method calls.
/// This solves the issue of repeatedly writing .expect("Failed to log")
/// and abstracts away the logger state for passing around via &mut self.
struct LoggerWrapper {
    inner: syslog::Logger,
}

impl LoggerWrapper {
    fn info(&mut self, message: &str) {
        // Handles the .expect internally, removing boilerplate from main
        self.inner.info(message).expect("Failed to log (info)");
    }

    fn warning(&mut self, message: &str) {
        self.inner.warning(message).expect("Failed to log (warning)");
