impl<'de> Deserialize<'de> for ResolvedB {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        use serde::de::Error;
        use std::collections::HashMap;

        let value = HashMap::<String, serde_json::Value>::deserialize(deserializer)?;

