            .get("path_list")
            .ok_or_else(|| Error::missing_field("path_list"))?;

        match path_entry {
            serde_json::Value::Array(arr) => {
                let paths: Result<Vec<String>, _> = arr
                    .iter()
                    .map(|v| v.as_str().map(String::from))
                    .collect();
                let paths: Result<Vec<PathBuf>, _> = paths?
                    .iter()
                    .map(|s| Ok(PathBuf::from(s)))
                    .collect();
                Ok(ResolvedB { path_list: paths? })
