                    |e| {
                        Error::custom(format!(
                            "Failed to parse {}: {}",
                            json_file,
                            e
                        ))
                    },
                )?;

                let paths_array = json_path
                    .trim_start_matches('/')
                    .split('/')
                    .filter(|s| !s.is_empty())
                    .try_fold(Some(external_data.clone()), |acc, key| {
                        acc.and_then(|val| val.get(key).cloned())
                    })
                    .ok_or_else(|| {
                        Error::custom(format!("Key {} not found", json_path))
                    })?;

                if let serde_json::Value::Array(arr) = paths_array {
                    let paths: Result<Vec<String>, _> = arr
