    println!("Starting Event Service...");

    let (sender, factory) = events_channel();
    let shutdown_signal = ShutdownSignal::new();

    // Spawn a producer to send events
    let producer_handle = tokio::spawn(async move {
        let mut counter = 0;
        loop {
            sleep(tokio::time::Duration::from_secs(2)).await;
            counter += 1;
            let msg = format!("Tick #{}", counter);
            sender.send(Event::from(msg.clone()));
            println!("Sent: {}", msg);
        }
    });

