    // This demonstrates how to combine the BroadcastStream with a shutdown signal
    let subscriber_tx = sender.clone();
    let shdl_rx = shutdown_signal.subscribe();

    let subscriber_handle = tokio::spawn(async move {
        let mut stream = factory.all_events();
        loop {
            tokio::select! {
                _ = shdl_rx.recv() => {
                    println!("[Subscriber] Received shutdown signal.");
                    break;
                },
                event_result = stream.next() => {
                    match event_result {
                        Some(Ok(evt)) => {
                            println!("[Subscriber] Received: {}", evt);
