    signal::ctrl_c().await.unwrap();
    println!("\nShutting down gracefully...");

    // 1. Signal tasks to stop listening (Cleanest way)
    shutdown_signal.stop();

    // 2. Join tasks to wait for them to finish processing shutdown
    subscriber_handle.abort(); // Force stop immediately as shown above

    // 3. Drop the Producer Handle to stop sending
    producer_handle.abort();

    // CRITICAL FOR ORIGINAL QUESTION:
    // The only way the *Stream* automatically closes via the Sender mechanism
    // is if ALL Sender clones are dropped.
