    // If you did NOT use the signal, dropping 'sender' here would NOT stop the stream
    // if 'subscriber_handle' still holds a clone internally or the Receiver is active.
    // The Receiver sees EOF only when ALL Senders are dropped.

    println!("[Main] Dropping original sender to close channel...");
    drop(sender);

    // Give time for the stream to see the sender drop
    sleep(tokio::time::Duration::from_millis(500)).await;

    println!("Shutdown complete.");
    Ok(())
