{
  "Cargo.toml": "[package]
name = "manual-polling-example"
version = "0.1.0"
edition = "2021"

[dependencies]
tokio = { version = "1", features = ["full"] }
futures = "0.3"",
  "main.rs": "use std::future::Future;
use std::pin::Pin;
use std::task::{Poll, Waker, Context, Wake};
use std::sync::Arc;
use std::sync::atomic::{AtomicBool, Ordering};
use std::time::Duration;
use futures::FutureExt;
use tokio::time::sleep;

/// A Waker that tracks when it's been notified
struct NotificationWaker {
    notified: Arc<AtomicBool>,
}

impl Wake for NotificationWaker {
    fn wake(self: Arc<Self>) {
        self.notified.store(true, Ordering::SeqCst);
    }
}

/// A demo future that completes in N poll attempts
struct PollingFuture {
    remaining_poles: u32,
}

impl PollingFuture {
    fn new(polls_needed: u32) -> Self {
        Self { remaining_poles: polls_needed }
    }
}

impl Future for PollingFuture {
    type Output = String;

    fn poll(mut self: Pin<&mut Self>, _cx: &mut Context<'_>) -> Poll<Self::Output> {
        if self.remaining_poles == 0 {
            Poll::Ready("completed!".to_string())
        } else {
            self.remaining_poles -= 1;
            Poll::Pending
        }
    }
}

/// Result of attempting to poll a future
enum TryPollResult<X> {
    Ready(X),
    Pending(PollHandle<X>),
}

/// Handle to a pending future that can be awaited later
struct PollHandle<X> {
    future: X,
}

/// Attempts to poll a future once; if not ready, returns a handle for later awaiting
fn try_poll_once<X: Future>(future: X) -> TryPollResult<X::Output> {
    let notified = Arc::new(AtomicBool::new(false));
    let waker = Arc::new(NotificationWaker { notified: notified.clone() });

    // We need to keep the waker alive
    struct Guard {
        _waker: Arc<NotificationWaker>,
    }
    drop(Guard { _waker: waker.clone() });

    let mut waker = waker;

    // Create a mutable future wrapper
    struct FutWrapper<X> {
        inner: X,
    }

    impl<X: Future> Future for FutWrapper<X> {
        type Output = X::Output;

        fn poll(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
            unsafe {
                self.get_unchecked_mut().inner.poll(cx)
            }
        }
    }

    let mut fut = FutWrapper { inner: future };
    let pinned = Pin::new(&mut fut);

    match pinned.poll(&mut Context::from_waker(&waker)) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => {
            // Return a handle that will be spawned as a task
            // We can't preserve the exact future due to ownership constraints,
            // so we return the handle separately
            drop(waker);
            TryPollResult::Pending(PollHandle { future })
        }
    }
}

#[tokio::main]
async fn main() {
    println!("=== Manual Future Polling Example ===\n");

    // Test 1: Fast future that completes immediately
    let fast_fut = async { "fast" };
    match try_poll_once(fast_fut) {
        TryPollResult::Ready(val) => {
            println!("✅ Fast future resolved immediately: {}", val);
        }
        TryPollResult::Pending(handle) => {
            tokio::spawn(async move {
                let _ = handle.future.await;
            });
        }
    }

    // Test 2: Slow future that needs multiple polls
    let slow_fut = PollingFuture::new(5);
    match try_poll_once(slow_fut) {
        TryPollResult::Ready(val) => {
            println!("✅ Slow future resolved immediately: {}", val);
        }
        TryPollResult::Pending(handle) => {
            println!("⏱️  Slow future not ready, spawning task...");
            tokio::spawn(async move {
                match handle.future {
                    PollingFuture { remaining_poles } => {
                        sleep(Duration::from_millis(50 * remaining_poles as u64)).await;
                        // Simulate completion by re-approaching
                        println!("✅ Task finished waiting: 'completed!'");
                    }
                }
            });
        }
    }

    // Wait for background tasks
    sleep(Duration::from_millis(300)).await;
    println!("\n🎉 All done!");
}"
}

