/// Converts a tokio::fs::File into a hyper Body via ReaderStream
fn make_streaming_body(mut file: File) -> impl HyperBody + Send + 'static {
    let stream = ReaderStream::with_capacity(&mut file, CHUNK_SIZE)
        .map_ok(|chunk| Chunk::from(chunk.to_vec()))
        .map_err(|e| {
            tracing::warn!(error = %e, "Error reading file chunk");
            std::io::Error::new(std::io::ErrorKind::Other, "Failed to read file chunk")
        });

    HyperBody::wrap_stream(stream)
}

struct Chunk(Vec<u8>);
impl Default for Chunk {
    fn default() -> Self {
        Self::new()
    }
}
impl Chunk {
    fn new() -> Self {
        Self(Vec::new())
    }
}

impl futures_core::Stream for Chunk {
    type Item = Result<Frame<Bytes>, std::io::Error>;

    fn poll_next(
        mut self: std::pin::Pin<&mut Self>,
        _cx: &mut std::task::Context<'_>,
    ) -> std::task::Poll<Option<Self::Item>> {
        Poll::Ready(None)
    }
}

async fn handle(req: Request<Empty<Full<Bytes>>>) -> Result<Response<HyperBody>, http::Error> {
    let uri_path = req.uri().path();

    match uri_path {
        "/" => {
            let resp = Response::builder()
                .status(StatusCode::OK)
                .header("content-type", "text/html")
                .body(Full::new(Bytes::from("Hello from static file server!\n")))
                .unwrap();
            Ok(resp)
        }

        path => {
            // Determine the file path
            let path_buf = PathBuf::from("./public").join(path.trim_start_matches('/'));

            if !path_buf.exists() || !path_buf.is_file() {
                return Response::builder()
                    .status(StatusCode::NOT_FOUND)
                    .body(Full::new(Bytes::from("File not found")))
                    .map_err(Into::into);
            }

            // Open file asynchronously
            let file_result = tokio::fs::OpenOptions::new()
                .read(true)
                .open(&path_buf)
                .await;

            let file = match file_result {
                Ok(f) => f,
                Err(e) => {
                    tracing::warn!(path = ?path_buf, error = %e, "Failed to open file");
                    return Response::builder()
                        .status(StatusCode::INTERNAL_SERVER_ERROR)
                        .body(Full::new(Bytes::from("Internal Server Error")))
                        .map_err(Into::into);
                }
            };

            // Generate response headers
            let content_type = mime_guess::from_path(&path_buf).first_or_octet_stream();

            // Get file metadata
            let meta_result = tokio::fs::metadata(&path_buf).await;
            let content_length = meta_result
                .map(|m| m.len())
                .unwrap_or_default();

            let builder = Response::builder()
                .status(StatusCode::OK)
                .header("content-type", content_type.as_ref())
                .header("accept-ranges", "bytes")
                .header("content-length", content_length);

            let body = make_streaming_body(file);
            let resp = builder.body(body).unwrap();

            Ok(resp)
        }
    }
}
