"main.rs": "// SOLUTION TO THE DESIGN DILEMMA:
// The `enum_dispatch` macro requires the Trait and the Enum to be defined in the same crate.
// To maintain your separation of concerns logically while respecting this constraint:
// 1. We merge the `al` (Abstract Layer - Trait) and `bl` (Business Layer - Enum) definitions
//    into a single cohesive 'interface' module. This effectively makes them one crate.
// 2. The `il` (Implementation Layer) remains separate and depends on the interface.
// 3. Rust allows cross-referencing modules within the same crate, resolving the apparent cycle.

mod interface;
mod implementations;

use interface::{Item, Rest};

fn main() {
    // Simulate configuration selection
    let items: Vec<Item> = vec![
        Item::Foo(implementations::Foo::new()),
        Item::Boo(implementations::Boo::new()),
    ];

    // Static dispatch via enum_dispatch
    for item in items {
        item.handle_request();
    }
}

/// This block represents the combined Abstract Layer and Business Layer.
/// According to `enum_dispatch` requirements, the Trait (AL) and the Enum (BL) 
/// must reside in the same compilation unit (crate). Separating them into 
/// different crates would prevent this macro from generating the static 
/// dispatch glue code correctly.
mod interface {
    // Import implementation types for the enum definition
    use super::implementations::{Foo, Boo};

    /// Abstract Layer: Defines the network service interface.
    pub trait Rest {
        fn handle_request(&self);
        fn get_name(&self) -> &'static str;
    }

    /// Business Layer: Aggregates implementations.
    #[enum_dispatch(Rest)]
    pub enum Item {
        Foo(Foo),
        Boo(Boo),
    }

    // Helper method to demonstrate polymorphic behavior
    pub fn run_services(items: &[Item]) {
        for item in items {
            // Polymorphism via static dispatch generated by enum_dispatch
            println!("Service [{}]: {}", item.get_name(), "Processing...");
            item.handle_request();
        }
    }
}

/// Implementation Layer: Contains specific structures implementing `Rest`.
/// It depends on `interface` for the trait definition.
mod implementations {
    // Import the trait to implement it
    use super::interface::Rest;

    pub struct Foo;

    impl Foo {
        pub fn new() -> Self {
            Foo
        }
    }

    impl Rest for Foo {
        fn handle_request(&self) {
            println!("Foo handling request (Static Dispatch)");
        }

        fn get_name(&self) -> &'static str {
            "Foo"
        }
    }

    pub struct Boo;

    impl Boo {
        pub fn new() -> Self {
            Boo
        }
    }

    impl Rest for Boo {
        fn handle_request(&self) {
            println!("Boo handling request (Static Dispatch)");
        }

        fn get_name(&self) -> &'static str {
            "Boo"
        }
    }
}
