    let mut quote_just_closed: bool = false;

    for c in input.chars() {
        if c == '\\'' {'
            in_single_quote = !in_single_quote;
            if !in_single_quote {
                quote_just_closed = true;
            } else {
                quote_just_closed = false;
            }
            continue;
        }

        // If we just closed a quote, we finish the current token accumulation
        if quote_just_closed {
            tokens.push(current_token);
            current_token.clear();
            quote_just_closed = false;
        }

        if !in_single_quote && c.is_whitespace() {
            // Outside quotes: whitespace acts as delimiter
            if !current_token.is_empty() {
                tokens.push(current_token);
                current_token.clear();
            }
            // Multiple consecutive spaces are ignored (don't push empty tokens)
        } else {
            // Inside quotes OR regular char outside quotes: append
            current_token.push(c);
        }
    }

    // Push remaining token if any
    if !current_token.is_empty() {
        tokens.push(current_token);
    } else if quote_just_closed {
        // Edge case: trailing empty quote '...''
        tokens.push(String::new());
    }

    tokens
}

fn main() {
    let test_cases = vec![
        " one  \" two  \"three    four",
        "\"one\"  \" two  \"three    four",
        "one  ''  two",
        "'",
        "",
    ];

    for cmd in test_cases {
        println!("Input: {:?}", cmd);
        let args = tokenize_shell_command(cmd);
        println!("Count: {}", args.len());
        for (i, arg) in args.iter().enumerate() {
            println!("  {}: '<{}>'", i + 1, arg);
        }
        println!();
    }
}"
}

