edition = "2021"

[dependencies]
axum = "0.7"
tokio = { version = "1", features = ["full"] }
headers = "0.3"
tracing = "0.1"
tracing-subscriber = "0.3"
tower = "0.4"
tower-http = "0.5"
hyper = { version = "1", features = ["full"] }",
"main.rs": "use axum::{
    extract::ws::{self, Message, WebSocket, WebSocketUpgrade},
    extract::TypedHeader,
    http::StatusCode,
    response::{IntoResponse, Response},
    routing::get,
    Router,
};
use headers::Origin;
use std::net::SocketAddr;
use tower_http::trace::TraceLayer;

#[tokio::main]
async fn main() {
    // Initialize tracing
    tracing_subscriber::fmt::init();

    // Allowed origins
    let allowed_origins = vec![
        "https://www.example.com",
        "https://localhost",
        "http://localhost:3000",
    ];

    let app = Router::new()
        .route("/ws", get(ws_handler))
        .layer(TraceLayer::new_for_http())
        .layer(axum::middleware::from_fn(check_origin_layer)); // Note: Middleware might not trigger during WS upgrade, relying on handler check for robustness.

    // Alternative: Handle logic inside handler for guaranteed execution.
    // Re-defining app without middleware for strict WS control demonstration:
    let app = Router::new()
        .route("/ws", get(ws_handler));

    let addr = SocketAddr::from(([127, 0, 0, 1], 3000));
    println!("Listening on {}", addr);

    let listener = tokio::net::TcpListener::bind(addr).await.unwrap();
    axum::serve(listener, app).await.unwrap();
}

// Handler to manage WebSocket connection with origin check
async fn ws_handler(
    ws: WebSocketUpgrade,
    origin: Option<TypedHeader<Origin>>,
) -> impl IntoResponse {
    // Check if Origin header exists and matches allowed list
    if let Some(TypedHeader(origin_val)) = origin {
        let origin_str = origin_val.to_string();
        if !allowed_origins.contains(&origin_str.as_str()) {
            return (
                StatusCode::FORBIDDEN,
                format!("Forbidden: Invalid origin. Allowed: {:?}", allowed_origins),
            )
            .into_response();
        }
    } else {
        return (StatusCode::FORBIDDEN, "Missing Origin header").into_response();
    }

    // Proceed with upgrade
    ws.on_upgrade(handle_socket)
}

// Fallback to find allowed_origins locally or pass as arg, simplified here
const ALLOWED_ORIGINS: &[&str] = &[
    "https://www.example.com",
    "https://localhost",
    "http://localhost:3000",
];

fn is_valid_origin(origin: &str) -> bool {
    ALLOWED_ORIGINS.contains(&origin)
}

async fn handle_socket(mut socket: WebSocket) {
    while let Ok(msg) = socket.recv().await {
        match msg {
            Message::Ping(_) => {
                let _ = socket.send(Message::Pong).await;
            }
            Message::Text(text) => {
                println!("Received: {}", text);
                let _ = socket.send(Message::text(format!("Echo: {}", text))).await;
            }
            Message::Close(frame) => {
                println!("Closing: {:?}", frame);
                break;
            }
            _ => {}
        }
    }
}"
}

