#[derive(Clone)]
pub struct Context(i32);

// Define a local trait to mimic AsyncFnOnce on stable Rust
// In stable, 'AsyncFnOnce' isn't available, so we define a compatible interface.
trait AsyncFnOnce<Ctx> {
    type Fut: Future<Output = ()> + Send;
    fn call(self, ctx: &mut Ctx) -> Self::Fut;
}

// Wrapper to box an async closure and ensure it implements Send
pub struct WrappedAsyncFn<F>(F);

impl<F, Args, Ctx> AsyncFnOnce<Ctx> for WrappedAsyncFn<F>
where
    F: FnOnce(Ctx) -> Pin<Box<dyn Future<Output = ()> + Send>> + Send,
    Ctx: Send,
