// This allows passing `async move { ... }` more directly
impl<Ctx> AsyncFnOnce<Ctx> for WrappedAsyncFn<Box<dyn FnOnce(Ctx) -> Pin<Box<dyn Future<Output = ()> + Send>>> > {
    type Fut = dyn Future<Output = ()> + Send;
    fn call(self, ctx: Ctx) -> Self::Fut {
        self.0(ctx)
    }
}

