    where
        Ctx: Send + 'static,
        F: FnOnce(Ctx) -> Pin<Box<dyn Future<Output = ()> + Send>> + Send + 'static,
    {
        WrappedAsyncFn(func)
    }

    // Helper to easily create a Boxed Future from an async move
    pub fn new_async_move<Ctx>(body: impl FnOnce(Ctx) + Send + 'static) -> WrappedAsyncFn<dyn FnOnce(Ctx) + Send>
    where
        Ctx: Send + 'static,
    {
        let wrapped = |ctx: Ctx| -> Pin<Box<dyn Future<Output = ()> + Send>> {
            Box::pin(async move {
                (body)(ctx);
            })
        };
        WrappedAsyncFn(wrapped)
    }
}

#[derive(Debug)]
pub enum InnerAsyncEvent {
    DoWithContext {
        block: Box<dyn FnOnce(Context) -> Pin<Box<dyn Future<Output = ()> + Send>> + Send + 'static>,
