    // We accept a closure that explicitly returns a boxed Send future to ensure safety
    // This replaces the 'impl AsyncFnOnce' which doesn't exist on stable
    block: impl FnOnce(&mut Context) + Send + 'static,
) -> Result<(), mpsc::SendError<InnerAsyncEvent>> {
    let boxed_block = Box::new(move |mut ctx: Context| {
        // Box the future of the async block explicitly to ensure Send
        Box::pin(async move {
            // Execute the blocking work here (wrapped in async to match type)
            block(&mut ctx);
        })
    });

    sender.send(InnerAsyncEvent::DoWithContext { block: boxed_block })
}

