pub fn with_context_async_trait(
    sender: mpsc::SyncSender<InnerAsyncEvent>,
    // We use a wrapper to simulate the trait object binding
    work: impl FnOnce(&mut Context) -> Pin<Box<dyn Future<Output = ()> + Send>> + Send,
) -> Result<(), mpsc::SendError<InnerAsyncEvent>> {
    sender.send(InnerAsyncEvent::DoWithContext {
        block: Box::new(move |ctx| work(ctx)),
    })
