            println!("Processing Async: {}", ctx.0);
            ctx.0 += 2;
        })
    });

    // Spawn a worker to process events (simulating thread send)
    tokio::spawn(async move {
        while let Some(event) = receiver.recv().await {
            match event {
                InnerAsyncEvent::DoWithContext { block } => {
                    let fut = block(Context(ctx_data));
                    fut.await;
                    println!("Job completed!");
                }
            }
        }
    });

    tokio::time::sleep(std::time::Duration::from_secs(1)).await;
}
