                    serde::de::Error::custom(format!("Fragment path '{}' not found", part))
                })?;
            }

            if let Some(arr) = current.as_array() {
                let paths: Vec<PathBuf> = arr.iter()
                    .filter_map(|v| v.as_str())
                    .map(PathBuf::from)
                    .collect();
                Ok(AResolved { path_list: paths })
            } else {
                Err(serde::de::Error::custom("Expected array at fragment path"))
            }
        } else {
