name = "shell-tokenizer"
version = "0.1.0"
edition = "2021"

[dependencies]",
  "main.rs": "/// Tokenizes a shell command line string with quote-aware parsing.
///
/// Mimics how the bash shell handles single-quoted substrings:
/// - Spaces outside quotes act as token delimiters
/// - Spaces inside quotes are preserved as part of the token
/// - Single quote characters themselves do not appear in tokens
///
/// # Example
///
/// ```
/// let result = tokenize(" one  ' two  'three    four");
/// assert_eq!(result, vec!["one", " two  three", "four"]);
/// ```
fn tokenize(input: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current_token = String::new();
    let mut in_quotes = false;

    for ch in input.chars() {
        if ch == '\'' {
            in_quotes = !in_quotes;
            continue; // Skip quote characters themselves
        }

        if in_quotes {
            // Inside quotes, preserve all characters including spaces
            current_token.push(ch);
        } else {
            // Outside quotes, treat spaces/tabs as delimiters
            if ch == ' ' || ch == '\t' {
                if !current_token.is_empty() {
                    tokens.push(std::mem::take(&mut current_token));
                }
            } else {
                // Non-whitespace character outside quotes builds token
                current_token.push(ch);
            }
        }
    }

    // Add final token if one remains pending
    if !current_token.is_empty() {
        tokens.push(current_token);
    }

    tokens
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_example_from_problem() {
        let result = tokenize(" one  ' two  'three    four");
        assert_eq!(result, vec!["one", " two  three", "four"]);
    }

    #[test]
    fn test_simple_quoted() {
        let result = tokenize("'hello world'");
        assert_eq!(result, vec!["hello world"]);
    }

    #[test]
    fn test_mixed_unquoted_quoted() {
        let result = tokenize("foo 'bar baz' qux");
        assert_eq!(result, vec!["foo", "bar baz", "qux"]);
    }

    #[test]
    fn test_adjacent_quote_non_space() {
        let result = tokenize("a'b'c");
        assert_eq!(result, vec!["ab", "c"]);
    }

    #[test]
    fn test_multiple_consecutive_spaces() {
        let result = tokenize("   hello     world   ");
        assert_eq!(result, vec!["hello", "world"]);
    }

    #[test]
    fn test_empty_string() {
        let result = tokenize("");
        assert_eq!(result, vec![]);
    }

    #[test]
    fn test_only_spaces() {
        let result = tokenize("    ");
        assert_eq!(result, vec![]);
    }
}

fn main() {
    let test_input = " one  ' two  'three    four";

    println!("Input: {}", test_input);
    println!();

    let tokens = tokenize(test_input);

    println!("Tokenized result:");
    for (i, token) in tokens.iter().enumerate() {
        println!("  [{}] <{}>", i + 1, token);
    }

    println!();
    println!("Total tokens: {}", tokens.len());

    // Run unit tests too
