        tests();
    }
}

#[cfg(test)]
fn tests() {
    tests::test_example_from_problem();
    tests::test_simple_quoted();
    tests::test_mixed_unquoted_quoted();
    tests::test_adjacent_quote_non_space();
    tests::test_multiple_consecutive_spaces();
    tests::test_empty_string();
    tests::test_only_spaces();
}"
