pub trait AsyncFnOnceCompat<'a>
where
    Self: Sized + Send + 'static,
{
    type Output;

    fn call_once(self, ctx: &'a mut Self::OutputType) -> Pin<Box<dyn Future<Output = Self::Output> + Send + 'a>>
    where
