    pub fn send_async_once(
        &self,
        block: impl FnOnce(&mut Context) -> Pin<Box<dyn Future<Output = ()> + Send + '_>> + Send + 'static,
    ) {
        let _ = self.sender.send(InnerAsyncEvent::DoWithContext {
            block: Box::new(move |ctx| block(ctx)),
        });
    }

