/// Flips the pixel line horizontally by treating the buffer as an array of 32-bit
/// words. This reduces the number of memory operations and loop iterations,
/// leveraging CPU word-sized operations for better efficiency.
pub fn flip_line(line_bytes: &mut [u8]) {
    debug_assert_eq!(line_bytes.len() % BYTES_PER_PIXEL, 0, "Buffer must be aligned to pixel size");
    debug_assert_eq!(line_bytes.len(), TOTAL_BYTES);

    // Treat the byte slice as a slice of 4-byte pixels (u32).
    // Safety: We know the length is a multiple of 4. We assume 4-byte alignment,
    // which is standard for image buffers on embedded hardware (ARM/AMD64).
    let pixels = unsafe {
