    // For a fixed size of 8, unrolling this explicitly helps the compiler
    // optimize branch prediction and vectorization.
    for i in 0..= (pixels.len() / 2) {
        if i == pixels.len() / 2 {
            break;
        }
        pixels.swap(i, pixels.len() - 1 - i);
    }
