    /// Generate Zobrist hash table from a seed.
    fn generate(seed: u64) -> Self {
        let mut rng = ChaCha8Rng::seed_from_u64(seed);

        // Piece × position: [color][square] = 8 colors × 6 squares = 48 entries
        let mut piece_position = [[0u64; 64]; 12];
