const FILE_PATH: &str = "output.json";

/// Loads the existing JSON file if it exists, otherwise returns an empty list.
/// This avoids the JSON syntax error caused by trying to append text to a closed array.
fn load_todos() -> Vec<String> {
    if !Path::new(FILE_PATH).exists() {
        return Vec::new();
    }

    let content = match fs::read_to_string(FILE_PATH) {
        Ok(s) => s,
        Err(e) => {
            eprintln!("Warning: Could not read file {}: {}. Starting new.", FILE_PATH, e);
            return Vec::new();
        }
    };

    // Handle empty files gracefully
    if content.trim().is_empty() {
        return Vec::new();
    }

    serde_json::from_str(&content).expect("Invalid JSON format in file.")
}

/// Serializes the vector to JSON and writes it to the file.
/// Note: Standard 'append' modes do not work for JSON arrays because 
/// you must modify the content between '[' and ']'. 
/// Therefore, we read-modify-write the entire file.
fn save_todos(todos: &Vec<String>) {
    let serialized = serde_json::to_string_pretty(todos).expect("Failed to serialize vector.");
    let mut file = fs::File::create(FILE_PATH).expect("Failed to create/write file.");
    file.write_all(serialized.as_bytes()).expect("Failed to write to file.");
}

