fn init_custom_logging() -> Result<(), SetLoggerError> {
    let mut builder = Builder::from_env(
        Env::default().default_filter_or("warn")
    );

    // Set a custom formatter that parses the file path to determine the module
    builder.format(|buf, record| {
        // Get the target (usually the module where log macro is defined)
        let target = record.target();

        // Try to parse the module from the file path
        let module = infer_module_from_file(record.file());

        // Use parsed module if valid, otherwise fallback to record target
        let effective_target = if let Some(mod_path) = module {
            mod_path
        } else {
            target
        };

        write!(
            buf,
            "[{}] [{}] {}: {}",
            chrono_lite_datetime(record.level()),
            effective_target,
            record.file().unwrap_or("unknown"),
            record.args()
        )
    });

    // Set the logger globally once
    let _ = log::set_logger(&CustomLogger {
        format: box_custom_formatter(builder.build_format()),
    });

    // Initialize the max level
    log::set_max_level(log::LevelFilter::Warn);

    Ok(())
}

// Helper struct to hold the formatter
struct CustomLogger {
    format: Box<dyn FnMut(&mut fmt::Write, &Record) -> fmt::Result>,
}

impl log::Logger for CustomLogger {
    fn enabled(&self, metadata: &log::Metadata) -> bool {
        log::enabled(metadata)
    }

    fn log(&self, record: &Record) {
        if !self.enabled(record.metadata()) {
            return;
