fn infer_module_from_file(file: Option<&str>) -> Option<String> {
    let path = file?;

    // Basic heuristic to convert src/main.rs or src/my_module/mod.rs to module path
    // Removes 'src/' prefix and '.rs' suffix
    // Converts '/' to '::'

    let stripped = path.strip_prefix("src/")?.strip_suffix(".rs")?;
    let replaced = stripped.replace('/', "::");

