impl<F> IntoHandler for F
where
    F: Fn(&Request) -> Response + Send + Sync + 'static,
{
    fn into_handler(self) -> HandlerInner {
        let f = Arc::new(move |req| {
            Box::pin(async move { self(req) })
        });
        HandlerInner::new(f)
    }
}

// Implementation for Asynchronous Functions:
// `F: Fn(&Request) -> Fut` where `Fut: Future<Output = Response>`
impl<F, Fut> IntoHandler for F
where
    F: Fn(&Request) -> Fut + Send + Sync + 'static,
    Fut: Future<Output = Response> + Send + 'static,
{
    fn into_handler(self) -> HandlerInner {
        let f = Arc::new(move |req| {
            // We need to ensure the returned future is pinned into a BoxFuture
            // The inner call returns `Fut`. We pin it.
            Box::pin(self(req))
