enum TryPollResult<X> {
    Ready(X),
    Pending,
}

struct NoopWaker;

impl Wake for NoopWaker {
    fn wake(self: Arc<Self>) {
        // Do nothing - this is fine for one-shot polling
    }
}

fn try_poll<F, X>(mut future: Pin<&mut F>, cx: &mut Context<'_>) -> TryPollResult<X>
where
    F: Future<Output = X> + Unpin,
{
    match future.as_mut().poll(cx) {
        Poll::Ready(value) => TryPollResult::Ready(value),
        Poll::Pending => TryPollResult::Pending,
    }
}

async fn long_running_task(sleep_ms: u64) -> String {
    sleep(Duration::from_millis(sleep_ms)).await;
    format!("Completed after {}ms", sleep_ms)
}

async fn short_running_task() -> i32 {
    sleep(Duration::from_millis(1)).await;
    42
}

#[tokio::main]
async fn main() {
    println!("=== Manual Future Polling Example ===\n");

    // Scenario 1: Fast future that completes quickly
    println!("Test 1: Fast task (1ms sleep)");
    {
        let mut fast_future = Box::pin(short_running_task());
        let waker = Arc::new(NoopWaker);
        let fake_waker = waker.clone();

        let mut cx = Context::from_waker(fake_waker.as_ref());

        match try_poll(Pin::new(&mut *fast_future), &mut cx) {
            TryPollResult::Ready(value) => {
                println!("✓ Future was ready immediately! Value: {}\n", value);
            }
            TryPollResult::Pending => {
                println!("? Future was not ready, spawning task...");
                let handle = tokio::spawn(fast_future);
                let result = handle.await.unwrap();
                println!("✓ Task completed: {}\n", result);
            }
        }
    }

