pub fn parse_date_to_int(d: &str) -> Result<i64, Box<dyn Error>> {
    // Determine if fractional seconds are present
    let format = if d.contains('.') {
        "%Y-%m-%dT%H:%M:%S.%f"
    } else {
        "%Y-%m-%dT%H:%M:%S"
