use serde::de::{self, Visitor, MapAccess};
use std::fmt;

// Nested enum-like structure B
#[derive(Debug, PartialEq)]
struct B {
    y: String,
}

impl<'de> Deserialize<'de> for B {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        struct BVisitor;

        impl<'de> Visitor<'de> for BVisitor {
            type Value = B;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("a map with \"y\" key")
            }

            fn visit_map<V>(self, mut map: V) -> Result<B, V::Error>
            where
                V: MapAccess<'de>,
            {
                let mut y: Option<String> = None;
                while let Some(key) = map.next_key::<String>()? {
                    match key.as_str() {
                        "y" => {
                            y = Some(map.next_value()?);
                        }
                        other => {
                            return Err(de::Error::unknown_field(
                                other,
                                &["y"],
                            ));
                        }
                    }
                }
                Ok(B {
                    y: y.ok_or_else(|| de::Error::missing_field("y"))?,
                })
            }
        }

        deserializer.deserialize_map(BVisitor)
    }
}

impl Serialize for B {
    fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
    where
        S: Serializer,
    {
        use serde::ser::SerializeMap;
        let mut map = serializer.serialize_map(Some(1))?;
        map.serialize_entry("y", &self.y)?;
        map.end()
    }
}

// Top-level structure A containing multiple Bs
#[derive(Debug, PartialEq)]
struct A {
    x: usize,
    b: Vec<B>,
}

impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        struct AVisitor;

        impl<'de> Visitor<'de> for AVisitor {
            type Value = A;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("a map with \"x\" and \"b\" keys")
            }

            fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
            where
                V: MapAccess<'de>,
            {
                let mut x: Option<usize> = None;
                let mut b: Option<Vec<B>> = None;

                while let Some(key) = map.next_key::<String>()? {
                    match key.as_str() {
                        "x" => {
                            if x.is_some() {
                                return Err(de::Error::duplicate_field("x"));
                            }
                            x = Some(map.next_value()?);
                        }
                        "b" => {
                            if b.is_some() {
                                return Err(de::Error::duplicate_field("b"));
                            }
                            // Deserialize a sequence of B values
                            let seq = map.next_value::<Vec<B>>()?;
                            b = Some(seq);
                        }
                        other => {
                            return Err(de::Error::unknown_field(
                                other,
                                &["x", "b"],
                            ));
                        }
                    }
                }

                Ok(A {
                    x: x.ok_or_else(|| de::Error::missing_field("x"))?,
                    b: b.ok_or_else(|| de::Error::missing_field("b"))?,
                })
            }
        }

        deserializer.deserialize_map(AVisitor)
    }
}

impl Serialize for A {
    fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
    where
        S: Serializer,
    {
        use serde::ser::SerializeMap;
        let mut map = serializer.serialize_map(Some(2))?;
        map.serialize_entry("x", &self.x)?;
        map.serialize_entry("b", &self.b)?;
        map.end()
    }
}

