    let output = toml::to_string_pretty(&a).expect("Failed to serialize");
    println!("Reserialized:\n{}\n", output);

    assert_eq!(
        a, A {
            x: 42,
            b: vec![
                B { y: "hello".to_string() },
                B { y: "world".to_string() },
            ],
        }
    );

    println!("✓ Nested custom deserialization works correctly!");
}
