use std::net::SocketAddr;
use tracing::info;

#[tokio::main]
async fn main() {
    // Initialize tracing subscriber to see logs in terminal
    tracing_subscriber::fmt::init();

    // Create the router
    // Apply the custom middleware layer to filter Origins before reaching handlers
    let app = Router::new()
        .route("/client/{session_id}", get(client_handler))
        .layer(middleware::from_fn(check_origin));

    // Start the server
    let addr = SocketAddr::from(([127, 0, 0, 1], 3000));
    info!("Server starting on {}", addr);

    let listener = tokio::net::TcpListener::bind(addr).await.expect("Failed to bind");
    axum::serve(listener, app).await.expect("Failed to serve");
}

/// Middleware Layer to check the Origin header for every request.
/// Returns 403 if the origin is not allowed.
async fn check_origin<B>(
    req: axum::http::Request<B>,
    next: Next<B>,
) -> Result<axum::response::Response, http::StatusCode> {
    let origin_header = req.headers().get(ORIGIN).and_then(|val| val.to_str().ok());

    match origin_header {
        // Validate the origin matches the allowed site
        Some(origin) if origin.starts_with("https://www.example.com") => {
            info!("Origin allowed: {}", origin);
            next.call(req).await.map(IntoResponse::into_response)
        }
        _ => {
            info!("Origin blocked: {:?}", origin_header);
            Err(http::StatusCode::FORBIDDEN)
        }
    }
}

async fn client_handler(
    ws: WebSocketUpgrade,
    axum::extract::Path(session_id): axum::extract::Path<String>,
) -> impl IntoResponse {
