/// In a production system, #[notion_property(...)] would be implemented via a ProcMacro.
#[derive(Serialize, Deserialize)]
struct MyUnit {
    #[serde(rename = "Name")]
    pub name: String,

    #[serde(rename = "Icon url")]
    pub icon_url: Option<String>,

    #[serde(rename = "Roles")]
    pub categories: Option<Vec<JsonValue>>,
}

// --- Conversion Logic ---

impl MyUnit {
    /// Converts the MyUnit struct into a HashMap matching Notion's expected Page Properties format.
    pub fn to_notion_map(&self) -> HashMap<String, PropertyValues> {
        let mut map = HashMap::new();

        // Handle "Name" (Title)
