            mention: None,
            annotations: None,
            href: None,
            plain_text: Some(self.name.clone()),
        }]);
        map.insert("Name".to_string(), title_value);

        // Handle "Icon url" (Url) - Optional
        if let Some(ref url) = self.icon_url {
