                    color: "gray_default".to_string(), // Default fallback
                    name: f.as_str().unwrap_or("").to_string(),
                })
                .collect();

            map.insert(
                "Roles".to_string(),
                PropertyValues::MultiSelect(selects),
            );
        }

        map
    }
}

