/// Tokenize a string in a quote-aware fashion similar to bash.
/// This splits input respecting single quotes:
/// - Whitespace outside quotes acts as delimiter
/// - Content inside quotes is preserved literally
/// - Quote characters themselves are removed from output
pub fn tokenize(input: &str) -> Vec<String> {
    let mut tokens = Vec::new();
    let mut current_token = String::new();
    let mut in_single_quote = false;

    for ch in input.chars() {
        if ch == '\'' {
            // Toggle quote state without adding quote to token
            in_single_quote = !in_single_quote;
            continue;
        }

        // Handle whitespace as delimiter only outside quotes
        if ch.is_whitespace() {
            if !current_token.is_empty() && !in_single_quote {
                tokens.push(current_token);
                current_token.clear();
            }
        } else {
            // All non-whitespace characters go into current token
            current_token.push(ch);
        }
    }

    // Push final token if any remains
    if !current_token.is_empty() {
        tokens.push(current_token);
    }

    tokens
}

