        write!(f, "{}", self.0)
    }
}

impl From<MyActixError> for Box<dyn std::error::Error + Send + Sync + 'static> {
    fn from(e: MyActixError) -> Self {
        Box::new(e)
    }
}

impl From<String> for MyActixError {
    fn from(s: String) -> Self {
        MyActixError(s)
    }
}

/// Simulate `actix_web::error::ErrorInternalServerError`
fn error_internal_server_error(msg: &str) -> MyActixError {
    MyActixError(msg.to_string())
}

/// Simulate `actix_web::error::ErrorBadRequest`
fn error_bad_request(msg: &impl std::fmt::Display) -> MyActixError {
    MyActixError(format!("{:?}", msg))
}

#[derive(Debug, Error)]
pub enum FrameworkError {
    #[error("{0}")]
    Error500(MyActixError),
    #[error("{0}")]
    Error400(MyActixError),
}

pub mod my_library {
    use super::{FrameworkError, error_bad_request, error_internal_server_error};
    use log::{Record, Metadata, Level};

    pub mod extensions {
        use super::*;
        use log::{LevelFilter, logger};

        pub mod logging {
            use super::*;

            pub trait LogChangeErrForRespExt {
                type R;

                #[track_caller]
                fn log_and_explain_400(self) -> Self::R;

                #[track_caller]
                fn log_hide_res(self) -> Self::R;
            }

            impl<T, E: std::error::Error + Display + 'static> LogChangeErrForRespExt for Result<T, E> {
                type R = Result<T, FrameworkError>;

                /// Logs the client error using custom log construction and returns the transformed error
                #[track_caller]
                fn log_and_explain_400(self) -> Self::R {
                    match self {
                        Ok(ok) => Ok(ok),
                        Err(err) => {
                            let loc = std::panic::Location::caller();

                            // Manual Record construction to override target/module
                            // We use the caller's file as the target to simulate "Calling Module"
                            let target = loc.file();

                            let meta = Metadata::builder()
                                .level(Level::Warn)
                                .target(target)
                                .modules_path(None)
                                .fields(Fields::new())
                                .build();

                            let record = Record::builder()
                                .metadata(meta)
                                .args(format_args!("Error in {}:{}", loc.file(), loc.line()))
                                .target(target)
                                .file(Some(loc.file()))
                                .line(loc.line())
                                .level(Level::Warn)
                                .build();

                            // Call the logger directly
                            if logger().enabled(&record.metadata()) {
                                logger().log(&record);
                            } else {
                                println!("[WARN {}] {}", target, record.args());
                            }

                            Err(FrameworkError::Error400(error_bad_request(&err)))
                        }
                    }
                }

                /// Logs the error using custom log construction (hides details)
                #[track_caller]
                fn log_hide_res(self) -> Self::R {
                    match self {
                        Ok(ok) => Ok(ok),
                        Err(_) => {
                            let loc = std::panic::Location::caller();
                            let target = loc.file();

                            let meta = Metadata::builder()
                                .level(Level::Warn)
                                .target(target)
                                .modules_path(None)
                                .fields(Fields::new())
                                .build();

                            let record = Record::builder()
                                .metadata(meta)
                                .args(format_args!("Internal server error at {}:{}", loc.file(), loc.line()))
                                .target(target)
                                .file(Some(loc.file()))
                                .line(loc.line())
                                .level(Level::Warn)
                                .build();

                            if logger().enabled(&record.metadata()) {
                                logger().log(&record);
                            }

                            Err(FrameworkError::Error500(error_internal_server_error("Unexpected error occured")))
                        }
                    }
                }
            }
        }
    }
}

