fn check_subset(target: Value, filter: Value) -> bool {
    match (target.as_object(), filter.as_object()) {
        (Some(t_obj), Some(f_obj)) => {
            // Iterate over filter keys. Every non-null key must exist and match in target.
            for (k, v) in f_obj.iter() {
