fn main() {
    // 1. Determine the filesystem path to script.py.
    // Since we need to pass a path to the Python interpreter, we create a temporary file.
    // This satisfies the requirement to package the script with the binary:
    // the content is compiled into the Rust binary, effectively "packaged" with it.
    // In a typical project, you would read this via include_str!("src/python/script.py")
    // instead of hardcoding it below.
    let py_script_content = r#"#!/usr/bin/env python3
import sys
print("Hello from your Rust-packaged Python script!")
print(f"Received arguments: {sys.argv}")
"#;

    // 2. Create a temporary file to hold the script content.
    // The `tempfile` crate ensures safe permissions and cleanup.
    let mut tmp_file = Builder::new()
        .prefix("rust_program_py_")
        .suffix(".py")
        .rand_chars(4)
        .tempfile()
        .expect("Failed to create temporary file");

    let script_path = tmp_file.path().to_path_buf();

    // 3. Write the packaged content to the filesystem path.
    tmp_file
        .write_all(py_script_content.as_bytes())
        .expect("Failed to write script content to temp file");

    // 4. Drop the file handle to close it securely before executing.
    // Important on Windows to allow deletion or modification by other processes.
    drop(tmp_file);

    // 5. Run the Python interpreter with the script path.
    let status = Command::new("python")
        .arg(&script_path)
        .stdin(Stdio::inherit())
        .stdout(Stdio::inherit())
        .stderr(Stdio::inherit())
        .status();

