//!
//! This example demonstrates how to replace `atomic-polyfill::AtomicUsize::fetch_add`
//! with `critical_section` and explains why `Ordering::Relaxed` is the correct choice.

use critical_section::{CriticalSection, RawMutex};
use static_cell::StaticCell;
use core::sync::atomic::{AtomicBool, Ordering};

/// A simple spinlock implementation using AtomicBool.
/// This is used to satisfy the `RawMutex` trait for testing purposes.
/// On `thumbv6m`, this would typically be implemented using CPSID/CPSIE (IRQ disable).
struct SpinLock {
    locked: AtomicBool,
}

impl RawMutex for SpinLock {
    /// Acquires the lock. Blocks if already held.
    unsafe fn acquire(&self) {
        // Spin until we successfully set the flag
        while self.locked.compare_exchange_weak(
            false,
            true,
            Ordering::SeqCst,
            Ordering::SeqCst,
        ).is_err()
        {
            // Busy wait
        }
    }

    /// Releases the lock.
    unsafe fn release(&self) {
        // Unlock the mutex for other contexts
        self.locked.store(false, Ordering::SeqCst);
    }
}

// Shared channel index state
static CHANNEL_INDEX_STATIC: StaticCell<core::sync::atomic::AtomicUsize> = StaticCell::new();
static MUTEX_STATIC: StaticCell<SpinLock> = StaticCell::new();

fn main() {
    // Initialize critical section implementation
    // This is required once per program execution
    // On Thumb-V6M, the `acquire`/`release` would use Cpsid/Cpsie to disable interrupts
    let spinlock = SpinLock {
        locked: AtomicBool::new(false),
    };

    MutexBuilder::set_impl(MUTEX_STATIC.init(spinlock));

    // Initialize our shared atomic counter
    let idx = CHANNEL_INDEX_STATIC.init(core::sync::atomic::AtomicUsize::new(0));

    println!("Testing critical_section replacement for AtomicUsize::fetch_add\n");

    // Original Code (atomic-polyfill):
    // let index = self.channel_index.fetch_add(1, Ordering::Relaxed);

    // Replacement Code (critical_section):
    let index = MutexBuilder::with(|_| {
        // IMPORTANT: Ordering::Relaxed is CORRECT here.
        // 
        // Reasoning:
        // 1. Mutual Exclusion: The `critical_section` block guarantees that no other thread
        //    or interrupt handler executes code accessing `self.channel_index` simultaneously.
        //    On Cortex-M, this is typically done by disabling interrupts (a full memory barrier).
        // 2. Barrier Effect: The entry and exit of the critical section act as implicit memory fences.
        //    Any reads/writes before the critical section will be visible to subsequent ones
        //    outside, and vice-versa.
        // 3. Semantic Match: The original `fetch_add(..., Ordering::Relaxed)` specified
        //    no cross-thread ordering requirements. Since the CS block serializes access,
        //    `Relaxed` correctly reflects that we only care about the atomicity of the
        //    read-modify-write sequence, not additional ordering constraints which are
        //    provided by the CS itself.
        // 4. Performance: `Relaxed` prevents the compiler/CPU from adding unnecessary
        //    memory barriers, matching the efficiency of the original polyfill.

        let old_val = idx.load(Ordering::Relaxed);
        idx.store(old_val + 1, Ordering::Relaxed);
        old_val
    });

    println!("Previous Index Value: {}", index);
    println!("Next Value Will Be: {}", index + 1);
    println!("Final State Matches Relaxed Semantics Inside Serializing Boundary.");
