/// Helper struct to manage setting the implementation statically in older critical_section versions
struct MutexBuilder;
impl MutexBuilder {
    fn set_impl<M: RawMutex + 'static>(_impl: &'static M) {
        // In v1.1, you usually do: critical_section::set_impl(impl)
        // Due to the static_cell interaction in this test harness, we assume the
        // raw implementation is globally registered for the session.
        // Note: In a real embedded scenario, `critical_section` handles static init via init macros
