           // critical_section::set_impl(unsafe { MUTEX_STATIC.get_unchecked() });
        }
        critical_section::set_impl(unsafe { MUTEX_STATIC.get_unchecked() });
    }

    #[inline(always)]
    fn with<F, R>(op: F) -> R 
    where
        F: FnOnce() -> R,
    {
        // This matches critical_section::with signature
        // We bypass the unsafe cast in the above block for safety
        // and use the standard lib wrapper if enabled, or fall back
        critical_section::with(op)
    }
