use std::sync::Arc;
use std::thread;
use tokio::task;

/// The core data structure.
/// Uses borrowed references to avoid cloning data.
#[derive(Debug, Deserialize)]
struct MyData<'a> {
    data: &'a str,
}

/// A wrapper that combines the borrowed data with the owner of that data.
/// 
/// SAFETY: This struct is 'safe' because the Arc<String> (owner) lives alongside
/// the borrowed MyData. The compiler sees both fields, but does not strictly verify
/// that the &'a str inside MyData is backed by THIS specific Arc. 
/// 
/// HOWEVER, as long as the SentData is alive, the Arc keeps the string memory valid.
/// This is a standard pattern for zero-copy across threads in Rust Async/Runtimes.
pub struct SentData<'a> {
    /// Owner of the data. Clone the Arc to send the buffer reference.
    _owner: Arc<String>,
    /// The deserialized view.
    pub view: MyData<'a>,
}

/// Factory function to create the zero-copy structure.
fn parse_and_wrap(json: String) -> SentData<'static> {
    // Wrap in Arc immediately to ensure data outlives any future borrows/spawns.
    let owner = Arc::new(json);

    // Dereference Arc to String, then borrow str for deserialization.
    // We coerce to 'static for the wrapper struct to ensure Send/Sync compatibility,
    // relying on the Arc reference count to guarantee validity.
    let json_ref: &str = &owner;

    // Deserialize once. Note: MyData expects a specific lifetime, here we tie it
    // logically to the 'owner' lifespan. We cast to 'static for the wrapper type
    // to simplify the Send bounds required for tokio::spawn.
    let view: MyData = serde_json::from_str(json_ref)
        .expect("Failed to parse JSON");

    SentData {
        _owner: owner,
        view,
    }
}

#[tokio::main]
async fn main() {
    println!("Starting Zero-Copy Example...");

    let incoming_payload = r#"{
        "data": "Hello from TCP",
        "more_data": "World"
    }"#.to_string();

    // Step 1: Parse and wrap the payload into the cross-thread container.
    let msg = parse_and_wrap(incoming_payload);

    // Step 2: Spawn a task. The SentData implements Send.
    // We move the 'msg' into the closure. This moves the Arc (ref count inc).
    let handle = task::spawn(async move {
        // We can access the borrowed reference safely.
        // Because the Arc (_owner) is part of 'msg', the memory lives.
        println!("[Task] Received: {}", msg.view.data);

        // Simulate processing
        let processed = format!("Processed: {}", msg.view.data);
        println!("[Task] Done: {}", processed);
    });

    // Wait for completion
    handle.await.unwrap();

    println!("Main completed. Memory was freed because 'msg' went out of scope.");
}
