use tokio::sync::mpsc;
use tokio::task::JoinHandle;

/// Shared configuration for graceful shutdown
#[derive(Clone)]
struct ShutdownConfig {
    abort_signal: Arc<AtomicBool>,
}

impl ShutdownConfig {
    fn new() -> Self {
        Self {
            abort_signal: Arc::new(AtomicBool::new(false)),
        }
    }

    fn should_stop(&self) -> bool {
        self.abort_signal.load(Ordering::SeqCst)
    }

    fn trigger_abort(&self) {
        self.abort_signal.store(true, Ordering::SeqCst);
    }
}

/// Simulated queue handler task
async fn queue_handler_task(shutdown_config: ShutdownConfig, mut rx: mpsc::Receiver<bool>) {
    info!("Queue handler started");

    loop {
        if shutdown_config.should_stop() {
            info!("Queue handler received shutdown signal");
            break;
        }

        // Simulate queue work
        tokio::select! {
            _ = tokio::time::sleep(Duration::from_secs(1)) => {
                debug!("Processing queue...");
            },
