        // Wait until we get shutdown signal
        loop {
            if let Ok(()) = rx.recv().await {
                info!("HTTP server received shutdown signal");
                break;
            }
        }

        // Attempt graceful shutdown
        drop(server);
        info!("HTTP server stopped gracefully");

        Ok(())
    });

    Ok((server, tx, server))
}

async fn handler_get() -> Result<HttpResponse, ActixError> {
    Ok(HttpResponse::Ok().body("Hello world!"))
}

async fn handler_health() -> Result<HttpResponse, ActixError> {
    Ok(HttpResponse::Ok().body("OK"))
}

#[actix_web::main]
async fn main() -> Result<(), Box<dyn Error>> {
    env_logger::init();
    info!("Starting application with graceful shutdown support");

    let shutdown_config = ShutdownConfig::new();

    // Spawn queue handler task
    let (_, queue_tx, mut queue_rx) = mpsc::channel::<bool>(1);
    let queue_handle = tokio::spawn(queue_handler_task(
        shutdown_config.clone(),
        queue_rx,
    ));

    // Spawn HTTP server task
    let (http_server, _, http_handle) = start_http_server()?;

    info!("All tasks spawned successfully");

    // Wait for Ctrl+C
    info!("Waiting for Ctrl+C... Press Ctrl+C to shutdown gracefully");
    ctrl_c().await?;

    info!("Received shutdown signal (Ctrl+C)");

    // Signal HTTP server to stop
    let _ = http_server.try_send(()).await;

    // Signal queue handler to stop
    let _ = queue_tx.send(()).await;

    // Trigger shutdown flag
    shutdown_config.trigger_abort();

    // Wait for tasks to finish
    info!("Waiting for tasks to complete shutdown...");

    match futures_util::future::join(http_handle, queue_handle).await {
        (Ok(res), Ok(_)) => {
            if let Err(e) = res {
                error!("HTTP server error during shutdown: {}", e);
            }
        }
        (Err(e), _) => {
            error!("HTTP server task failed: {}", e);
        }
        (_, Err(e)) => {
            error!("Queue handler task failed: {}", e);
        }
    }

    info!("All tasks stopped. Shutting down.");
    Ok(())
}"
