    fn hint(
        &self,
        _line: &str,
        _pos: usize,
        ctx: &Context,
    ) -> Option<Self::Hint> {
        let cursor_pos = ctx.edit_buffer().len();
        if cursor_pos == 0 {
            return None;
        }

        let prev_word = ctx.edit_buffer()[..cursor_pos]
            .rsplit(' ')
            .next()
            .unwrap_or("");

        match prev_word {
            "FROM" | "JOIN" => Some("table ".to_string()),
            "WHERE" | "ORDER BY" => Some("condition ".to_string()),
            "SELECT" | "INTO" => Some("column ".to_string()),
            _ => None,
