    fn complete(
        &self,
        line: &str,
        pos: usize,
        _ctx: &Context,
    ) -> Result<(usize, Vec<Pair>), CompletableError> {
        let word_before_cursor = get_current_word(line, pos);

        if word_before_cursor.starts_with('b') {
            Ok((pos - word_before_cursor.len(), vec![Pair::new("book".to_string(), "book".to_string())]))
        } else if word_before_cursor.starts_with('t') {
            Ok((pos - word_before_cursor.len(), vec![Pair::new("title".to_string(), "title".to_string())]))
        } else if word_before_cursor.starts_with('o') {
            Ok((pos - word_before_cursor.len(), vec![Pair::new("order".to_string(), "order".to_string())]))
        } else {
            Ok((pos, vec![]))
        }
    }
}

fn get_current_word(line: &str, pos: usize) -> String {
    if pos == 0 {
        return String::new();
    }

    let chars: Vec<char> = line.chars().collect();
    let mut end = pos;

    while end > 0 && (chars[end - 1].is_alphanumeric() || chars[end - 1] == '_') {
        end -= 1;
    }

    if end == pos {
