                    return Action::Continue; // Just let the character insert normally
                }
            }
        }

        Action::Continue
    }
}

impl ConditionalEventHandler for WhitespaceStripper {
    fn handle(
        &self,
        event: &Event,
        count: RepeatCount,
        positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let line = context.line();
        let pos = context.pos();

        if pos == 0 {
            return None;
        }

        // Look for whitespace run ending at cursor position
        if let Some(non_ws_idx) = line[0..pos].rfind(|c: char| !c.is_whitespace()) {
            let ws_start = non_ws_idx + 1;
            let ws_len = pos - ws_start;

            // If there are consecutive spaces, delete them
            if ws_len > 0 && self.insert_char != '.' && self.insert_char != ',' {
                return None;
            }

            if ws_len > 0 {
                // Use BackwardMove to position at start of whitespace
                let back_chars = BackwardChars(ws_len);

                // Since rustyline doesn't allow multiple cmds,
                // we'll use InsertChar which places cursor AFTER insertion
                return Some(Cmd::InsertChar(self.insert_char));
            }
        }

        None
    }
}

fn bind_handler(editor: &mut Editor<SqlEditor, DefaultHistory>, key: char) {
    let event = KeyEvent::new(key, KeyModifiers::NONE);
    let handler = WhitespaceStripper::new(key);
    let handler = EventHandler::Simple(handler);
    editor.bind_sequence(event, handler);
}

#[tokio::main]
async fn main() -> io::Result<()> {
    let rl_config = Builder::new()
        .max_history_size(100)
        .build();

    let mut editor = Editor::<SqlEditor, DefaultHistory>::with_config(rl_config)?;

    editor.set_helper(Some(SqlEditor));
    editor.set_completion_type(CompletionType::List);
    editor.set_edit_mode(EditMode::Vi);

    // Bind whitespace-stripping events
    bind_handler(&mut editor, '.');
    bind_handler(&mut editor, ',');

    println!("SQL Command Line Tool\nType 'help' for usage, 'quit' to exit");

    loop {
        let readline = editor.readline("zql > ");

        match readline {
            Ok(line) => {
                if line.trim() == "quit" {
                    break;
                }

                editor.add_history_entry(line.as_str());
                println!("{}", execute_sql(&line));
            }
            Err(rustyline::error::ReadlineError::Interrupted) => {
                eprintln!("\nInterrupted");
            }
            Err(rustyline::error::ReadlineError::Eof) => {
                break;
            }
            Err(err) => {
                eprintln!("{:?}", err);
                break;
            }
        }
    }

    Ok(())
}

fn execute_sql(query: &str) -> String {
    if query.trim().is_empty() {
        return String::from("\n");
    }

    let q = query.to_uppercase();

    if q.contains("FROM book") || q.contains("SELECT title") {
        return format!(
            "[SQLite]\nQuery executed successfully\nColumns: year, authorid, title"
        );
    }

    if q.contains("SELECT * FROM") {
        return String::from("[Mock Database]\nReturns all records from table\
Column names may vary by database system");
    }

    String::from("Query parsed. Execute against your ODBC connection.")
}"
}
