    let tree = SourceFile::parse(input_code);

    // Collect edits to apply
    let mut edits: Vec<(TextRange, String)> = Vec::new();

    // Helper to process UseTrees
    fn collect_edits(
        tree: &ra_ap_syntax::SyntaxNode,
        parent_path: Option<String>,
        edits: &mut Vec<(TextRange, String)>
    ) {
        for child in tree.children() {
            if let Some(use_stmt) = Use::cast(child) {
                if let Some(use_tree) = use_stmt.use_tree() {
                    analyze_use_tree(&use_tree, parent_path.as_deref(), use_stmt.syntax(), edits);
                }
            }
            collect_edits(&child, parent_path, edits);
        }
    }

    fn analyze_use_tree(
        tree: &ra_ap_syntax::ast::UseTree,
        _parent: Option<&str>,
        syntax_node: &ra_ap_syntax::SyntaxNode,
        edits: &mut Vec<(TextRange, String)>
    ) {
        let text = syntax_node.text_range();
        let range = text.into();
        let src = text.as_str();

        // Check if path starts with vexide::devices
        if src.starts_with("vexide::devices") || src.starts_with("vexide::{") && src.contains("devices::") {
            let mut new_src = src.to_string();
            // Rule: Flatten vexide::devices -> vexide
            if new_src.contains("vexide::devices") {
                new_src = new_src.replace("vexide::devices::", "vexide::");
                new_src = new_src.replace("vexide::devices;", "vexide;");
                new_src = new_src.replace("vexide::devices", "vexide");
            }
            // Specific cleanup for list context to remove extra braces if only devices item existed (basic heuristic)
            if new_src.contains("use vexide::{devices}") {
                 new_src = new_src.replace("use vexide::{devices}", "use vexide::{ devices }").unwrap();
            }

            // Apply edit
            edits.push((range, new_src));
        }
    }

    // Gather all relevant nodes first (to avoid range shifting during recursion if not sorted)
    // Note: In a real tool, we would use a visitor pattern that collects ranges.
    // Here we traverse the root.
    collect_edits(&tree.syntax(), None, &mut edits);

    // Sort by range start in descending order to apply edits from end to start
    edits.sort_by_key(|(r, _)| std::cmp::Reverse(r.start()));

    let mut result = input_code.to_string();
