        // Adjust range for current string length changes
        // Since we iterate from end, previous ranges don't shift relative to start
        // However, our ranges were calculated against the ORIGINAL string.
        // Applying edits sequentially from end to start on the string works if lengths match offsets.
        // But replacement length != original length!
        // We must recalculate positions.
        // Simplification for this demo: We assume edits are disjoint.
        result.replace_range(range, &replacement);
    }

    println!("Modified:\n{}\n", result);
