use std::task::{Context, Poll};
use std::sync::Arc;

use futures::future::ready;
use tokio::time::{sleep, Duration};

// Custom Waker implementation that does nothing
struct NoopWake;

impl std::task::Wake for NoopWake {
    fn wake(arc_self: Arc<Self>) {
        // Intentionally empty, we only check readiness once here
    }
}

// Enum to represent the result of the try_poll operation
enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// Attempts to poll a future synchronously.
/// If it returns Ready, the value is returned.
/// If it returns Pending, the function logs and spawns the future
/// to be awaited in a background task instead of blocking.
async fn process_future<F: std::future::Future + Send + 'static>(mut fut: F) -> TryPollResult<F::Output>
where
    <F as std::future::Future>::Output: Send,
{
    // Pin the future so it can be polled safely across multiple calls
    let pinned_fut = unsafe {
        Pin::new_unchecked(std::mem::transmute::<_, Pin<&mut _>>(&mut fut))
    };

    // Create a waker that does nothing (we don't want to actually wake ourselves)
    let waker = Arc::new(NoopWake);
    let mut cx = Context::from_waker(waker.as_ref());

    // Perform the manual poll
    match pinned_fut.poll(&mut cx) {
        Poll::Ready(val) => {
            println!("-> Future resolved immediately synchronously!");
            TryPollResult::Ready(val)
        }
        Poll::Pending => {
            println!("-> Future yielded. Spawning to await asynchronously...");
            // Because we returned Pending, we did not consume the future yet.
            // However, to be safe and idiomatic, we should pin the future again
            // before moving it into the spawned task to ensure safety.

            // Re-pin for the async block
            let to_spawn = async move {
                // Safety: We know this is valid because we took ownership previously
                let mut fut_pin = Pin::new(&mut fut);
                let val = fut_pin.await;
                println!("-> Spawned task completed with value: {:?}", val);
            };
            tokio::spawn(to_spawn);
            TryPollResult::Pending
        }
    }
}

// Example fast future (ready immediately)
async fn fast_job() -> String {
    "I am ready".to_string()
}

// Example slow future (sleeps before resolving)
async fn slow_job() -> i32 {
    sleep(Duration::from_secs(2)).await;
    42
}

#[tokio::main]
async fn main() {
    println!("Starting manual polling examples...\n");

    // Scenario 1: Immediate resolution
    let result1 = process_future(fast_job()).await;
    if let TryPollResult::Ready(val) = result1 {
        println!("Main logic used value: {}\n", val);
    }

    // Scenario 2: Needs spawning
    let result2 = process_future(slow_job()).await;
    if let TryPollResult::Pending = result2 {
        println!("Main logic did not wait, handled by spawn.\n");
    }

    // Keep runtime alive long enough for spawned task to complete
    sleep(Duration::from_secs(3)).await;
    println!("Runtime finished.");
}
"
}
