use axum::http::header;
use futures::{SinkExt, StreamExt};
use http_body_util::BodyExt;
use tokio::net::TcpListener;
use tower_http::cors::{Any, CorsLayer};

// Allow list for origins
const ALLOWED_ORIGINS: &[&str] = &["https://www.example.com"];

#[tokio::main]
async fn main() {
    // Set up CORS layer for regular HTTP traffic
    // Note: This does NOT prevent unauthorized WebSocket upgrades.
    let cors = CorsLayer::new()
        .allow_origin("https://www.example.com".parse().unwrap())
        .allow_methods([axum::http::Method::GET, axum::http::Method::POST])
        .allow_headers([header::CONTENT_TYPE]);

    // Custom middleware to check Origin headers specifically for WebSocket endpoints
    // This addresses the requirement to filter origins on the router layer.
    async fn check_origin(
        mut req: Request<axum::body::Body>,
        next: Next<axum::body::Body>,
    ) -> Result<impl IntoResponse, axum::response::ErrorResponse> {
        // Only enforce strict origin check on our WebSocket routes
        // Adjust paths as needed
        if req.uri().path().starts_with("/client/") {
            if let Some(origin_val) = req.headers().get(header::ORIGIN) {
                let origin_str = origin_val.to_str().unwrap_or("");

                // Check if origin is in allowed list
                let is_allowed = ALLOWED_ORIGINS.iter().any(|&allowed| {
                    allowed == origin_str ||
                    // Optionally allow subdomains or variations
                    origin_str.starts_with("https://") && !allowed.contains("*")
                });

                // Simple check against exact match for security demo
                let is_exact_match = ALLOWED_ORIGINS.contains(&origin_str);

                if !is_exact_match {
                    return Err((axum::http::StatusCode::FORBIDDEN, "Origin not allowed").into_response());
                }
            } else {
                // Missing Origin header is suspicious for browser-based WSS
                 return Err((axum::http::StatusCode::BAD_REQUEST, "Missing Origin header").into_response());
            }
        }

        next.call(req).await
    }

    let app = Router::new()
        .route("/client/{session_id}", get(client_handler))
        .route("/health", get(|| async { "OK" }))
        .layer(cors)
        .layer(tower_http::trace::TraceLayer::new_for_http())
        .layer(tower::ServiceExt::clone().boxed());

    // Apply middleware
    let app = Router::new()
        .merge(app)
        .layer(axum::middleware::from_fn(check_origin));

    let listener = TcpListener::bind("127.0.0.1:3000").await.unwrap();
    println!("Listening on http://localhost:3000");

    axum::serve(listener, app).await.unwrap();
}

async fn client_handler(ws: WebSocketUpgrade) -> impl IntoResponse {
    ws.on_upgrade(|socket| async move {
        // Basic WebSocket echo handler
        let (mut sender, mut receiver) = socket.split();

        let send_fut = async move {
            while let Some(val) = receiver.next().await {
                if let Ok(msg) = val {
                    if sender.send(msg).await.is_err() {
                        break;
                    }
                }
            }
        };

        send_fut.await;
    })
}"
}
