pin_project! {
    pub struct StageFuture<F> {
        #[pin]
        future: F,
        parent_span: tracing::Span,
    }
}

impl<F, T> Future for StageFuture<F>
where
    F: Future<Output = T>,
{
    type Output = T;

    fn poll(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
        let this = self.project();
        // Re-attach parent span on poll
        let _guard = this.parent_span.enter();
        this.future.poll(cx)
    }
}

#[derive(Debug, Clone)]
pub struct RequestContext {
    pub request_id: String,
    pub parent_span: tracing::Span,
}

impl RequestContext {
    pub fn new(request_id: String) -> Self {
        let span = info_span!("request", id = %request_id);
        Self { request_id, parent_span: span } 
    }

    pub fn with_stage(&self, stage_name: &str) -> StageFutureBox {
        let stage_span = self.parent_span.clone().or_else(|| {
            info_span!("stage", name = %stage_name, req_id = %self.request_id)
        });
        StageFutureBox {
            parent_span: stage_span,
        }
    }
}

pub type StageFutureBox = Box<dyn Future<Output = ()>>;

async fn stage_one(ctx: RequestContext) -> Result<(), String> {
    let _span = ctx.parent_span.clone();
    info!("Stage one starting");
    tokio::time::sleep(tokio::time::Duration::from_millis(10)).await;
    Ok(())
}

async fn stage_two(ctx: RequestContext) -> Result<(), String> {
    let _span = ctx.parent_span.clone();
    info!("Stage two starting");
    tokio::time::sleep(tokio::time::Duration::from_millis(10)).await;
    stage_three(ctx).await?;
    Ok(())
}

async fn stage_three(ctx: RequestContext) -> Result<(), String> {
    let _span = ctx.parent_span.clone();
    info!("Stage three starting (upstream call)");
    Ok(())
}

async fn run_proxy_cycle(ctx: RequestContext) {
    info!(req_id = %ctx.request_id, "Starting proxy request cycle");
    ctx.parent_span.in_scope(|| {
        async {
            stage_one(ctx.clone()).await.unwrap();
            tokio::task::spawn(stage_two(ctx.clone()));
        }
        .instrument(info_span!("proxy_cycle"))
        .await;
    });
    info!(req_id = %ctx.request_id, "Proxy request cycle completed");
}

struct RequestHandler {
    tx: mpsc::UnboundedSender<RequestContext>,
}

impl RequestHandler {
    async fn accept_request(&self) -> Option<RequestContext> {
        let mut rx = self.tx.subscribe();
        match rx.recv().await {
            Some(ctx) => Some(ctx),
            None => None,
        }
    }
}

#[tokio::main]
async fn main() {
