use std::time::Duration;
use tokio::sync::mpsc;

/// Defines a struct that borrows data with a specific lifetime.
/// We avoid DeserializeOwned to allow borrowed references.
#[derive(Deserialize, Debug)]
struct MyData<'a> {
    data: &'a str,
    more_data: &'a str,
}

#[tokio::main]
async fn main() {
    // Create channel to pass String payload across threads
    let (tx, mut rx) = mpsc::channel::<String>(1);

    // Simulate incoming JSON payload
    let payload = r#"{"data": "hello", "more_data": "world"}"#.to_string();

    // Spawn a worker task. The String ownership moves into this closure.
    let handle = tokio::spawn(async move {
        // Loop until the channel is empty (sender dropped)
        while let Some(json_str) = rx.recv().await {
            // To deserialize into a struct with &str (lifetime param),
            // we cannot use serde_json::from_str because it requires DeserializeOwned.
            // Instead, we use the low-level Deserializer API which respects Deserialize bounds.
            let mut deserializer = serde_json::Deserializer::from_str(&json_str);

            // This deserializes, binding the lifetime of MyData to the lifetime of json_str
            // which is local to this async task scope. No data is cloned, only referenced.
            let my_data: MyData<'_> = match MyData::deserialize(&mut deserializer) {
                Ok(data) => data,
                Err(e) => {
                    println!("Deserialization error: {}", e);
                    continue;
                }
            };

            // The struct MyData borrows directly from json_str. Safe because
            // json_str lives in this task's scope until this block ends.
            println!("Processed: {} | {}", my_data.data, my_data.more_data);

            // Simulate async work using the borrowed data
            tokio::time::sleep(Duration::from_millis(50)).await;
        }
        // Implicitly drops json_str here, satisfying lifetime requirements
    });

    // Send the data to the spawned task
    tx.send(payload).await.map_err(|_| panic!("Channel failed"))?.ok();

    // Close the send side to trigger rx.recv() to return None eventually
    drop(tx);

    // Wait for the spawned task to complete
    handle.await.map_err(|_| panic!("Task panicked"))?;

    println!("All tasks completed successfully.");
}"
