"main.rs": "use serde::{Deserialize, Deserializer};
use serde::de::{MapAccess, Visitor};
use std::fmt;

// We derive Deserialize for B to keep the demo focused on the nesting in A,
// demonstrating how to delegate to the inner type.
#[derive(Serialize, Deserialize, Debug)]
enum B {
    Variant1(String),
    Variant2,
}

struct A {
    x: usize,
    b: Vec<B>,
}

// Manual implementation of Deserialize to demonstrate custom Visitor logic
impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        struct AVisitor;

        impl<'de> Visitor<'de> for AVisitor {
            type Value = A;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("a map")
            }

            fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
            where
                V: MapAccess<'de>,
            {
                let mut val = A {
                    x: 0,
                    b: Vec::new(),
                };

                // Iterate over keys
                while let Some(key) = map.next_key::<String>()? {
                    match key.as_str() {
                        "x" => {
                            // Deserialize x directly
                            val.x = map.next_value()?;
                        }
                        "b" => {
                            // CONNECTION POINT: Explicitly specify the target type (Vec<B>)
                            // This calls the Deserialize implementation for B recursively
                            val.b = map.next_value::<Vec<B>>()?;
                        }
                        _ => {
                            // Skip unexpected fields gracefully
                            let _: String = map.next_value()?;
                        }
                    }
                }
                Ok(val)
            }
        }

        deserializer.deserialize_map(AVisitor)
    }
}

fn main() {
    // Note: Default Serde enum format is externally tagged: ["Name", value]
    let json_data = r#"
    {
        "x": 42,
        "b": [
            ["Variant1", "Hello"],
            "Variant2"
        ]
    }
    "#;

    let result: Result<A, _> = serde_json::from_str(json_data);
    match result {
        Ok(a) => {
            println!("Deserialized A: {:?}", a);
            println!("Nested B vec length: {}", a.b.len());

            // Verify serialize works as expected with our A deriving Serialize
            let out = serde_json::to_string_pretty(&a).unwrap();
            println!("Round-trip Serialized:\n{}", out);
        }
        Err(e) => eprintln!("Failed to deserialize: {}", e),
    }
}"
