use critical_section::Mutex;
use core::sync::atomic::{AtomicUsize, Ordering};

// Minimal panic handler required for no_std targets
#[panic_handler]
fn panic(_info: &core::panic::PanicInfo) -> ! {
    loop {}
}

struct ChannelManager {
    channel_index: AtomicUsize,
}

impl ChannelManager {
    pub const fn new() -> Self {
        ChannelManager {
            channel_index: AtomicUsize::new(0),
        }
    }

    /// Emulates fetch_add using critical_section.
    ///
    /// Ordering Choice: SeqCst
    /// ------------------------
    /// You previously used `Ordering::Relaxed`. While `critical_section` provides
    /// the necessary synchronization (mutual exclusion + full fence) for the block,
    /// using `Ordering::SeqCst` for the inner load/store is the recommended approach
    /// when emulating atomics with locks. This is because:
    ///
    /// 1. **Intent Clarity:** It explicitly marks the load/store as part of a
    ///    globally synchronized operation, documenting that the variable's state
    ///    is fully visible across critical sections.
    ///
    /// 2. **Compiler Barriers:** While `critical_section` prevents hardware reordering
    ///    via disabling interrupts, `SeqCst` provides the strongest compiler-level
    ///    memory fence. This prevents the compiler from reordering accesses in ways
    ///    that might expose partially updated state if the critical section
    ///    implementation were ever changed or if strict visibility is needed
    ///    without relying solely on the CS macro expansion for reordering control.
    ///
    /// 3. **Safety Margin:** It avoids introducing subtle race conditions related
    ///    to how `Relaxed` interacts with the CS fence at the compiler level,
    ///    ensuring the atomicity property holds regardless of compiler optimizations.
    ///
    /// Effectively, `critical_section` wraps the body in a full fence. Using `SeqCst`
    /// inside aligns the atomic primitives with that fence behavior.
    pub fn fetch_channel_index(&self) -> usize {
        critical_section::with(|_| {
            let old_val = self.channel_index.load(Ordering::SeqCst);
            // Perform the add
            let new_val = old_val.wrapping_add(1);
            self.channel_index.store(new_val, Ordering::SeqCst);
            old_val
        })
    }
}

/// Dummy main to satisfy build requirements. In a real RP2040 project,
/// you would use #[panic_handler] and #[entry] from cortex-m-rt.
