    let mut tokens = Vec::new();
    let mut buffer = String::new();
    let mut in_quotes = false;

    for c in cmd.chars() {
        if !in_quotes && c.is_whitespace() {
            if !buffer.is_empty() {
                tokens.push(buffer);
                buffer = String::new();
            }
            continue;
        }

        match c {
            '\'' => {
                in_quotes = !in_quotes;
            }
            _ => {
                buffer.push(c);
            }
