/// Polls a future immediately; if pending, spawns it as a new async task
async fn try_poll_and_spawn<F, T>(future: F) -> T
where
    F: Future<Output = T> + Send + 'static,
    T: Send + 'static,
{
    match try_poll_future(future) {
