fn try_poll_future<F, T>(future: F) -> TryPollResult<T>
where
    F: Future<Output = T>,
{
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);
    let mut pinned = Box::pin(future);

    match Pin::new(&mut pinned).poll(&mut cx) {
        Poll::Ready(value) => TryPollResult::Ready(value),
        Poll::Pending => TryPollResult::Deferred(pinned),
    }
}

