    // We want to remove 'devices' if it is at index 1 (after 'vexide')
    let mut should_modify = false;
    let modified_segments: Vec<String> = if current_segments.len() >= 2 
        && current_segments[0] == "vexide" && current_segments[1] == "devices" 
    {
        should_modify = true;
        let mut mods = current_segments.clone();
        mods.remove(1); // Remove 'devices'
        mods
    } else {
        current_segments
    };

    // Join segments
    let base_path = if should_modify {
        modified_segments.join("::")
    } else {
        current_segments.join("::")
    };

    // Determine if we output a brace block or a flat path
    let has_children = tree.use_tree_list().is_some();
    let is_glob = tree.star_token().is_some();
    let rename = tree.alias();

    let mut result_parts = vec![base_path];

    // Handle Glob
    if is_glob {
        // If it was vexide::devices::*, and we flatten to vexide::*, it works.
        // But if it was vexide::devices::Inner::*, it becomes vexide::Inner::*
        result_parts.push("*".to_string());
    }

    // Handle Children (Braces)
    if has_children {
        let list = tree.use_tree_list()?;
        let children: Vec<_> = list.use_trees()
            .map(|t| {
                // Pass empty prefix for children because they are relative to the current resolved path
                // Wait, standard use syntax: `use outer::{inner::Thing}`.
                // If `outer` is `vexide`, `inner` is `devices`...
                // In `use_tree_list`, the `UseTree`s don't carry parent path info automatically.
                // We need to recurse.

                // NOTE: Handling the prefix propagation inside children is crucial.
                // If we had `use vexide::devices::{smart}`, `smart` effectively becomes `vexide::devices::smart`.
                // After flattening `vexide::devices` -> `vexide`, `smart` becomes `vexide::smart`.
                // So we MUST pass the *modified* base_path to children.

                if let Some(child_resolved) = render_modified_use_tree(
                    &t,
                    // Pass the modified segments (minus glob flag context)
                    if should_modify {
                        modified_segments.clone()
                    } else {
                        current_segments.clone()
                    },
                    true
                ) {
                    child_resolved
                } else {
                    // Fallback for malformed or unhandled
                    t.syntax().text().to_string()
                }
            })
            .collect();

        if !children.is_empty() {
            let inner = children.join(",");
            result_parts.push(format!("{{ {} }}", inner));
        }
    }

    // Handle Rename `as`
    if let Some(rename) = rename {
        result_parts.push(format!(" as {}", rename.name()));
    }

    Some(result_parts.join("::"))
}
