  "main.rs": "use std::io;
use std::sync::mpsc::{self, Sender, Receiver};
use std::thread;
use signal_hook::consts::{SIGINT, SIGTERM};
use signal_hook::iterator::Signals;
use termion::raw::IntoRawMode;
use termion::input::TermRead;
use termion::event::Key;

#[derive(Debug)]
enum Message {
    Key(char),
    Signal(i32),
    Quit,
}

fn yield_signals(sender: Sender<Message>) -> thread::JoinHandle<()> {
    let mut signals = Signals::new(&[SIGINT, SIGTERM]).unwrap();
    let handle = thread::spawn(move || {
        for sig in signals.forever() {
            sender.send(Message::Signal(sig)).ok();
        }
    });
    handle
}

fn yield_keys(sender: Sender<Message>, rx: Receiver<Option<Message>>) -> thread::JoinHandle<()> {
    let stdout = io::stdout().into_raw_mode().unwrap();
    let stdin = io::stdin();

    let handle = thread::spawn(move || {
        for event in stdin.events() {
            if let Ok(termion::event::Event::Key(Key::Char(c))) = event {
                sender.send(Message::Key(c)).ok();
            }
            // Check for shutdown signal
            if let Some(quit_msg) = rx.recv().ok() {
                match quit_msg {
                    Some(Message::Quit) => {
                        println!("\nKey listener stopped.");
                        break;
                    },
                    _ => {},
                }
            }
        }
    });
    handle
}

fn main() {
    let (sender, receiver): (Sender<Message>, Receiver<Message>) = mpsc::channel();

    // Create a separate channel to allow shutdown signaling from the main loop
    let (stop_sender, stop_receiver): (Sender<Option<Message>>, Receiver<Option<Message>>) = mpsc::channel();

    // Spawn key listener thread
    let key_thread = yield_keys(sender.clone(), stop_receiver);

    // Spawn signal listener thread
    let _signal_thread = yield_signals(sender.clone());

    // Event loop
    for msg in receiver {
        match msg {
            Message::Key(c) => {
                println!("Got key: {}", c);
                if c == 'q' || c == 'Q' {
                    println!("User requested quit via 'q'.");
                    stop_sender.send(Some(Message::Quit)).ok();
                    println!("Sending shutdown signal to all threads...");
                    break;
                }
            },
            Message::Signal(sig) => {
                println!("Received signal: {}", sig);
                if sig == SIGINT as i32 || sig == SIGTERM as i32 {
                    println!("Received exit signal.");
                    stop_sender.send(Some(Message::Quit)).ok();
                    break;
                }
            },
            Message::Quit => {
                println!("Quitting...");
                break;
            }
        }
    }

    // Clean up: wait for threads to finish
    key_thread.join().unwrap();
    println!("All threads joined. Application exiting.");
}
"}

