fn get_by_pointer<'a>(root: &'a Value, pointer: &str) -> Option<&'a Value> {
    if pointer.is_empty() || pointer == "/" {
        return Some(root);
    }
    if !pointer.starts_with('/') {
        return None;
    }

    let segments: Vec<&str> = pointer.split('/').skip(1).collect();
    let mut current = root;

    for seg in segments {
        match current {
            Value::Object(map) => {
                current = map.get(seg)?;
            },
            _ => return None,
        }
    }
    Some(current)
}

fn resolve_refs(val: &Value) -> Result<Value, Box<dyn std::error::Error>> {
    match val {
        Value::Object(obj) => {
            let mut new_obj = serde_json::Map::new();
            for (k, v) in obj.iter() {
                if k == "$ref" {
                    if let Value::String(ref_path) = v {
                        let (file_part, pointer_part) = if let Some(idx) = ref_path.find('#') {
                            (&ref_path[..idx], &ref_path[idx..])
                        } else {
                            (ref_path, "")
                        };

                        let file_data = fs::read_to_string(file_part)?;
                        let file_val: Value = from_str(&file_data)?;

                        if pointer_part.is_empty() {
                            return Ok(file_val);
                        } else {
