                                return resolve_refs(target);
                            } else {
                                return Err("Pointer navigation failed".into());
                            }
                        }
                    }
                } else {
                    new_obj.insert(k.clone(), resolve_refs(v)?);
                }
            }
            Ok(Value::Object(new_obj))
        },
        Value::Array(arr) => {
            let new_arr: Vec<Value> = arr.iter().map(|v| resolve_refs(v)).collect::<Result<_, _>>()?;
            Ok(Value::Array(new_arr))
        },
        _ => Ok(val.clone()),
