/// Wrapper function to accept any async closure and wrap it safely for threading.
/// 
/// Note: `AsyncFnOnce` is an unstable feature (nightly only).
/// On stable Rust, we simulate this by accepting `FnOnce` returning a `Future`
/// and enforcing `Send` bounds on the boxed future inside.
pub fn with_context_async(
    sender: &Arc<mpsc::Sender<InnerAsyncEvent>>,
    block: impl FnOnce(&mut Context) -> Pin<Box<dyn futures::Future<Output = ()> + Send>> + Send + 'static,
) {
    let _ = sender.try_send(InnerAsyncEvent::DoWithContext { block });
}

/// Simplified version that accepts a generic FnOnce returning a Future,
/// performs the boxing/boxing coercion internally to hide complexity.
/// 
/// This is the "nice" way to wrap AsyncFnOnce-like closures on stable.
pub fn with_context_async_simplified<T, Fut>(
    sender: &mpsc::Sender<InnerAsyncEvent>,
    block: T,
) where
    T: FnOnce(&mut Context) -> Fut + Send + 'static,
    Fut: futures::Future<Output = ()> + Send + 'static,
{
    // Move the closure into a boxed trait object that enforces Send.
    // We use a move closure here to capture `block`.
    let wrapped_block = Box::new(move |ctx: &mut Context| {
        // Run the async block immediately to generate the Future
        // Then box and pin it to satisfy the Event contract
        let fut = block(ctx);
        futures::future::FutureExt::boxed(fut)
    });

    let _ = sender.send(InnerAsyncEvent::DoWithContext { block: wrapped_block });
}

