const CHUNK_SIZE: usize = 65_536;

// Custom AsyncRead wrapper that handles file reads in chunks
struct FileReader {
    file: File,
}

impl AsyncRead for FileReader {
    fn poll_read(
        mut self: std::pin::Pin<&mut Self>,
        cx: &mut Context<'_>,
        buf: &mut tokio::io::ReadBuf<'_>,
    ) -> Poll<std::result::Result<(), io::Error>> {
        // We need to work around the fact that we want to limit chunk size
        let inner_buf = vec![0u8; CHUNK_SIZE];
        let remaining = inner_buf.len().saturating_sub(buf.filled().len());

        // Tokio File doesn't support partial reads directly on buffer
        // So we read full chunks and copy into the output buffer
        let result = poll_read_chunks(&mut self.file, cx, buf);

        // Map results appropriately
        match result {
            Poll::Ready(Ok(_)) => Poll::Ready(Ok(())),
            Poll::Pending => Poll::Pending,
            Poll::Ready(Err(e)) => Poll::Ready(Err(e)),
        }
    }
}

fn poll_read_chunks(
    file: &mut File,
    cx: &mut Context<'_>,
    buf: &mut tokio::io::ReadBuf<'_>,
) -> Poll<std::result::Result<(), io::Error>> {
    use std::future::poll_fn;
    use std::io::{Error, Seek, SeekFrom};

    let future = async {
        let mut remaining = buf.remaining();
        while remaining > 0 {
            let pos = file.stream_position().await?;
            file.seek(SeekFrom::Current(0)).await?;

            // Read directly into the buffer
            let sliced = unsafe {
                std::slice::from_raw_parts_mut(
                    buf.filled_mut().as_mut_ptr().add(buf.filled().len()),
                    remaining,
                )
            };

            // We must not use unsafe slice access, so let's use a safer approach
            let mut temp_buf = vec![0u8; remaining.min(CHUNK_SIZE)];

            let n = tokio::io::AsyncReadExt::read_at(file, &mut temp_buf, pos).await?;

            if n == 0 {
                break;
            }

            let filled_slice = unsafe {
                std::slice::from_raw_parts_mut(
                    buf.filled_mut().as_mut_ptr().add(buf.filled().len()),
                    n,
                )
            };

            filled_slice.copy_from_slice(&temp_buf[..n]);
            buf.advance(n);
            remaining -= n;
        }
        Ok::<_, Error>(())
    };

    poll_fn(|cx| {
        let future = Box::pin(future.as_future());
        futures_lite::future::block_on(future)
    })
