                                normal = calculate_hit_normal(
                                    result.intersection,
                                    transform.rotation,
                                    cube_mesh,
                                );
                            }
                        }
                    }
                }

                if let Some(hit_entity) = closest_entity {
                    let Ok(transform) = entity_q.get(hit_entity) else { continue; };
                    let face_offset = normal * 0.5;
                    let face_center = transform.translation + transform.rotation * face_offset;

                    let rotation = construct_flush_rotation(normal, transform.rotation);

                    gizmos.rect(
                        Transform::from_translation(face_center + normal * 0.01)
                            .with_rotation(rotation)
                            .to_isometry(),
                        Vec2::new(1.0, 1.0),
                        Color::WHITE,
                    );
                }
            }
        }
    }
}

fn construct_flush_rotation(hit_normal: Vec3, block_rotation: Quat) -> Quat {
    // Define which local axis maps to which hit normal for each face
    let face_normals = [
        vec3(1.0, 0.0, 0.0),   // Right
        vec3(-1.0, 0.0, 0.0),  // Left
        vec3(0.0, 1.0, 0.0),   // Top
        vec3(0.0, -1.0, 0.0),  // Bottom
        vec3(0.0, 0.0, 1.0),   // Front
        vec3(0.0, 0.0, -1.0),  // Back
    ];

    let normalized_normal = hit_normal.normalize();

    for (i, face_normal) in face_normals.iter().enumerate() {
        if normalized_normal.dot(*face_normal).abs() > 0.99 {
            // Build a rotation that aligns the selected local face to world normal
            let local_forward = match i {
                0 | 1 => Vec3::X,
                2 | 3 => Vec3::Y,
                4 | 5 => Vec3::Z,
                _ => Vec3::Z,
            };

            let mut new_forward = Vec3::Z;
            match (i % 2 == 0) || (i >= 4) {
                false => new_forward = Vec3::NEG_Z,
                _ => new_forward = Vec3::Z,
            }

            let face_dir = match i {
                0 => Vec3::X,
                1 => Vec3::NEG_X,
                2 => Vec3::Y,
                3 => Vec3::NEG_Y,
                4 => Vec3::Z,
                _ => Vec3::NEG_Z,
            };

            return Quat::from_rotation_arc(new_forward, normalized_normal);
        }
    }

    block_rotation
}

fn calculate_hit_normal(intersection: RayIntersectionResult, block_rot: Quat, box_mesh: Cuboid) -> Vec3 {
    if let Some(hit_transformed) = intersection.point.as_ref() {
        let local_hit = block_rot.inverse() * (*hit_transformed - block_rot * Vec3::ZERO);
        let (x, y, z) = (local_hit.x, local_hit.y, local_hit.z);

        if x.abs() > y.abs() && x.abs() > z.abs() {
            return if x > 0.0 { Vec3::X } else { Vec3::NEG_X };
        } else if y.abs() > z.abs() {
            return if y > 0.0 { Vec3::Y } else { Vec3::NEG_Y };
        } else {
            return if z > 0.0 { Vec3::Z } else { Vec3::NEG_Z };
        };
    }
    Vec3::Z
}

