/// Represents the abstraction for sending events.
pub struct EventSender {
    tx: Sender<Event>,
}

impl EventSender {
    pub fn send(&self, event: Event) {
        let _ = self.tx.send(event);
    }
}

/// Factory for creating broadcast streams (SSE).
pub struct EventStreamFactory {
    tx: Sender<Event>,
}

impl EventStreamFactory {
    /// Creates a stream listening to events. The stream completes when all senders are dropped.
    pub fn all_events(&self) -> impl futures::Stream<Item = Result<Event, broadcast::RecvError>> {
        BroadcastStream::new(self.tx.subscribe()).filter_map(|result| match result {
            Ok(event) => Some(Ok(event)),
            Err(_) => None,
        })
    }
}

/// Internal event type
#[derive(Debug, Clone)]
struct Event {
    id: u64,
    message: String,
}

/// Central manager to hold the Sender lifecycles.
/// Dropping this manager ensures all clones of the Sender are destroyed,
/// signaling the BroadcastStream to complete.
pub struct EventChannel {
    pub sender: EventSender,
    pub factory: EventStreamFactory,
}

pub fn events_channel() -> EventChannel {
    let (tx, _) = broadcast::channel::<Event>(20);
    EventChannel {
        sender: EventSender { tx: tx.clone() },
        factory: EventStreamFactory { tx },
    }
}

// Signal handler task
async fn listen_for_shutdown() {
    println!("Waiting for shutdown signal...");
    #[cfg(unix)]
    {
        let mut sigterm = tokio::signal::unix::signal(tokio::signal::unix::SignalKind::terminate()).expect("Failed to register signal handler");
        let mut sigint = tokio::signal::unix::signal(tokio::signal::unix::SignalKind::interrupt()).expect("Failed to register signal handler");

        tokio::select! {
            _ = sigterm.recv() => println!("Received SIGTERM"),
            _ = sigint.recv() => println!("Received SIGINT"),
        }
    }
    #[cfg(not(unix))]
    {
        // Fallback for non-Unix systems (Windows/macOS support)
        let _ = tokio::signal::ctrl_c().await;
        println!("Received CTRL+C");
    }
}

#[tokio::main]
async fn main() {
    let channel = events_channel();

    // Spawn a task to simulate receiving SSE streams
    let stream_handle_1 = {
        let factory = channel.factory.clone();
        tokio::spawn(async move {
            let mut stream = factory.all_events();
            println!("[Client 1] Listening for events...");
            while let Some(result) = stream.next().await {
                match result {
                    Ok(evt) => println!("[Client 1] Got: {:?}", evt.message),
                    Err(_) => break, // Stream ended (senders dropped)
                }
            }
            println!("[Client 1] Stream closed.");
        })
    };

    let stream_handle_2 = {
        let factory = channel.factory.clone();
        tokio::spawn(async move {
            let mut stream = factory.all_events();
            println!("[Client 2] Listening for events...");
            while let Some(result) = stream.next().await {
                match result {
                    Ok(evt) => println!("[Client 2] Got: {:?}", evt.message),
                    Err(_) => break,
                }
            }
            println!("[Client 2] Stream closed.");
        })
    };

    // Spawn producer task
    let producer = {
        let sender = channel.sender.clone();
        tokio::spawn(async move {
            println!("Producer running...");
            for i in 0..10u64 {
                let event = Event { id: i, message: format!("Hello #{}", i) };
                sender.send(event);
                tokio::time::sleep(std::time::Duration::from_millis(500)).await;
            }
        })
    };

    // Spawn shutdown listener
    let shutdown_signal = tokio::spawn(listen_for_shutdown());

    // Wait briefly to allow streams to start before shutdown in demo
    tokio::time::sleep(std::time::Duration::from_millis(2000)).await;
